--- 提升品质任务集合 统一格式，同品;隔开 多个品|隔开
function LxHeroCtrl:_GetSplitQualityUpQuest(qualityUpQuest)
    if string.isempty(qualityUpQuest) then
        return {}
    end
    local quality, questIdList, maxQuality
    local map = {}
    local qualityUpQuestList = string.split(qualityUpQuest, ";")
    for i, v in ipairs(qualityUpQuestList) do
        v = string.split(v, ":")
        quality = checknumber(v[1])
        questIdList = string.split(v[2], "|")
        local questList = {}
        for idx, questId in ipairs(questIdList) do
            table.insert(questList, checknumber(questId))
        end
        map[quality] = {
            questList = questList,
        }
        if maxQuality and maxQuality < quality then
            maxQuality = quality
        elseif not maxQuality then
            maxQuality = quality
        end
    end
    return map, maxQuality
end

--- 提升品质物品消耗 统一格式，同品;隔开 多个品|隔开
function LxHeroCtrl:_GetSplitQualityUpItem(qualityUpItem)
    if string.isempty(qualityUpItem) then
        return {}
    end
    local quality, splitItemList
    local map = {}
    local qualityUpItemList = string.split(qualityUpItem, ";")
    for i, v in ipairs(qualityUpItemList) do
        v = string.split(v, ":")
        quality = checknumber(v[1])
        splitItemList = string.split(v[2], "|")
        local upItemList = {}
        for idx, val in ipairs(splitItemList) do
            table.insert(upItemList, LxDataHelper.ParseItem(val))
        end
        map[quality] = {
            upItemList = upItemList,
        }
    end
    return map
end

--- 星级解锁的技能
function LxHeroCtrl:_GetSplitStarSkill(starSkill)
    if not starSkill or #starSkill < 1 then
        return {}
    end
    local map = {}
    local list = {}
    local unLockStarMap = {}
    local skillType
    for i, v in ipairs(starSkill) do
        v = string.split(v, "=")
        skillType = checknumber(v[1])
        local data = {
            --- 技能类型
            skillType = skillType,
            --- 技能id
            skillId = checknumber(v[2]),
            --- 解锁星级
            unlockStar = checknumber(v[3]),
        }
        table.insert(list, data)
        unLockStarMap[data.unlockStar] = data
        local skillTypeList = map[skillType]
        if not skillTypeList then
            skillTypeList = {}
            map[skillType] = skillTypeList
        end
        table.insert(skillTypeList, data)
    end
    return list, map,unLockStarMap
end

function LxHeroCtrl:_GetSplitClassSkill(classSkill)
    if not classSkill or #classSkill < 1 then
        return {}
    end
    local list = {}
    local map = {}
    local skillType,unlockClass
    for i,v in ipairs(classSkill) do
        v = string.split(v,"=")
        skillType = checknumber(v[1])
        unlockClass = checknumber(v[3])
        local data = {
            --- 技能类型
            skillType = skillType,
            --- 技能id
            skillId = checknumber(v[2]),
            --- 解锁阶级
            unlockClass = unlockClass,
        }
        table.insert(list,data)
        map[unlockClass] = data
    end
    return list,map
end

function LxHeroCtrl:GetInitSplitHeroRef(refId)
    local heroRefMap = self._heroRefMap[refId]
    if not heroRefMap then
        local ref = GameTable.CharacterRef[refId]
        if ref then
            heroRefMap = {}
            local quality = ref.quality
            local qualityUpQuestMap, maxQuality = self:_GetSplitQualityUpQuest(ref.qualityUpQuest, quality)
            local skillList, skillMap,unLockStarMap = self:_GetSplitStarSkill(ref.starSkill)
            local classSkill = self:_GetSplitClassSkill(ref.classSkill)
            heroRefMap = {
                quality = quality,
                qualityUpQuestMap = qualityUpQuestMap,
                qualityUpItemMap = self:_GetSplitQualityUpItem(ref.qualityUpItem, quality),
                maxQuality = maxQuality,
                starSkill = skillList,
                skillMap = skillMap,
                classSkill = classSkill,
                unLockStarMap = unLockStarMap,
                unlockNeed = LxDataHelper.ParseItem(ref.unlockNeed)
            }
            self._heroRefMap[refId] = heroRefMap
        end
    end
    return heroRefMap
end

function LxHeroCtrl:GetSplitHeroRefByHeroObj(heroObj)
    return self:GetInitSplitHeroRef(heroObj.refId)
end

