---@param heroObj LxHeroObj
function LxHeroCtrl:GetClassSkill(heroObj,addGrade)
    local splitHRef = self:GetSplitHeroRefByHeroObj(heroObj)
    if not splitHRef then return  end

    local maxSkillId
    local grade = heroObj:GetHeroGrade()
    if addGrade then
        grade = grade + addGrade
    end
    local classSkill = splitHRef.classSkill
    for i,v in ipairs(classSkill) do
        if v.unlockClass <= grade then
            maxSkillId = v.skillId
        end
    end
    local isLock = maxSkillId == nil
    if isLock then
        maxSkillId = classSkill[1] and classSkill[1].skillId
    end
    return {
        isOpen = not isLock,
        skill = maxSkillId,
        skillTypeStr = self:GetSkillTypeStr(SkillTypeEnums.Advance,maxSkillId)
    }
end

function LxHeroCtrl:GetHeroSkillListByRefId(refId,star,grade)
    local splitHRef = self:GetInitSplitHeroRef(refId)
    if not splitHRef then return {} end

    local skillMap = splitHRef.skillMap
    if not skillMap then return {} end

    local skillList = {}
    local skillData = self:_GetHeroSkillInfo(star, skillMap[SkillTypeEnums.Initiative1])
    if skillData then
        table.insert(skillList, skillData)
    end

    skillData = self:_GetHeroSkillInfo(star, skillMap[SkillTypeEnums.Initiative2])
    if skillData then
        table.insert(skillList, skillData)
    end

    skillData = self:_GetHeroSkillInfo(star, skillMap[SkillTypeEnums.Passivity])
    if skillData then
        table.insert(skillList, skillData)
    end

    local maxSkillId
    local classSkill = splitHRef.classSkill
    for i,v in ipairs(classSkill) do
        if v.unlockClass <= grade then
            maxSkillId = v.skillId
        end
    end
    local isLock = maxSkillId == nil
    if isLock then
        maxSkillId = classSkill[1].skillId
    end
    table.insert(skillList, {
        isOpen = not isLock,
        skill = maxSkillId,
        skillTypeStr = self:GetSkillTypeStr(SkillTypeEnums.Advance,maxSkillId)
    })
    return skillList
end

function LxHeroCtrl:_GetHeroSkillInfo(star, skillList)
    if not skillList or #skillList < 1 then
        return
    end
    local dSkill
    for i, v in ipairs(skillList) do
        if star >= v.unlockStar then
            dSkill = v
        end
    end
    local isOpen = dSkill ~= nil
    if not dSkill then
        dSkill = skillList[1]
    end
    return { isOpen = isOpen, skill = dSkill.skillId, skillTypeStr = self:GetSkillTypeStr(dSkill.skillType,dSkill.skillId) }
end

--- 根据技能类型获取描述
function LxHeroCtrl:GetSkillTypeStr(skillType,skillId)
    local skillTypeStr
    if skillType == SkillTypeEnums.Initiative1 then
        if skillId then
            skillTypeStr = LxDataHelper.GetSkillName(skillId)
        else
            skillTypeStr = I18nText(2434)
        end
    elseif skillType == SkillTypeEnums.Initiative2 then
        if skillId then
            skillTypeStr = LxDataHelper.GetSkillName(skillId)
        else
            skillTypeStr = I18nText(2435)
        end
    elseif skillType == SkillTypeEnums.Passivity then
        skillTypeStr = I18nText(2436)
    elseif skillType == SkillTypeEnums.Strategy then
        skillTypeStr = I18nText(2437)
    elseif skillType == SkillTypeEnums.Fetter then
    elseif skillType == SkillTypeEnums.Advance then
        skillTypeStr = I18nText(2490)
    end
    return skillTypeStr
end

