function LxHeroCtrl:GetBaseAttrList(heroAttrMap)
    local list = {}
    ---  英雄界面固定展示的4种基础属性
    local showList = {1, 3, 2, 4}--GameTable.CharacterConfigRef.herolvShowAttr
    local baseAttrs = {}
    for i, v in ipairs(showList) do
        local _t = string.split(v, "=")
        table.insert(baseAttrs, checknumber(_t[1]))
    end


    local attrMap = heroAttrMap
    local attr
    local attrValue
    for i, attrRefId in ipairs(baseAttrs) do
        attrValue = attrMap[attrRefId] or 0
        attr = ModuleCenter.Common:NewAttrObj({
            refId = attrRefId,
            value = attrValue
        })
        table.insert(list, attr)
    end
    return list
end

function LxHeroCtrl:GetPreviewBaseAttrList(heroAttrMap, heroRef)
    local list = {}
    ---  攻击、生命、速度、物理防御、魔法防御
    local showList = GameTable.CharacterConfigRef.herolvShowAttr
    local baseAttrs = {}
    local heroInitAttributes = LxDataHelper.ParseAttrList(heroRef.initAttribute)
    for i, v in ipairs(heroInitAttributes) do
        table.insert(baseAttrs, v.refId)
    end

    local attrMap = heroAttrMap
    local attr
    local attrValue
    for i, attrRefId in ipairs(baseAttrs) do
        attrValue = attrMap[attrRefId].value or 0
        attrValue = math.floor(attrValue + 0.5)
        attr = ModuleCenter.Common:NewAttrObj({
            refId = attrRefId,
            value = attrValue
        })
        table.insert(list, attr)
    end
    return list
end

---@param heroAttrMap table 通过英雄计算的公式，属性为 11 ~ 99，需要重新转换为 1 ~ 10
function LxHeroCtrl:GetPreviewPower(heroAttrMap,level, heroObj)
    local mode = ModuleCenter.Hero:GetCurMode()
    if mode == HeroModeType.Compete then
        return self:GetHeroPower(heroObj)
    end
    local changeAttrMap = {}
    for k,v in pairs(heroAttrMap) do
        if k > 100 or k < 11 then
            changeAttrMap[k] = v.value
        else
            --- 11 ~ 99
            k = k % 10
            if k > 0 then
                changeAttrMap[k] = v.value
            end
        end
    end
    --- attrRefId 2 coefficient
    local coefficientMap = self:GetRoleLevelAttrMap(level)
    local power = 0
    local coefficient
    for k,v in pairs(changeAttrMap) do
        coefficient = coefficientMap[k] or 1
        power = power + v * coefficient
    end
    return power
end

---@param heroObj LxHeroObj 升级消耗返回，受 heroUpLvlTime 控制
---@param rpCheck boolean 是否为升星检查
---@return table
---@field tabType number 改变底部页签，比如去升星, 按照 UIHeroTrainMainCtrl 里面的 TabBtnTypeEnum 定义来
---@field payItemList V_Item[] 道具列表
---@field state number 状态码 -4:已满级 ; -3:等级限制 ; -2:去升星 ; -1:道具不足 ; 0:可进阶 ; 1:可升级
---@field target number 操作类型 1:升级 ; 2:进阶 ; 3:升星
---@field btnName string 按钮名字
---@field msg string 点击按钮飘字
---@field bGray boolean 是否置灰
---@field upLv number state 字段 == 1，返回升级数
function LxHeroCtrl:GetHeroUpLvExpendListByHeroObj(heroObj,rpCheck)
    if not heroObj or not heroObj.id then return {} end

    local maxLevel = LxDataHelper.GetHeroStarMaxLevelByHeroObj(heroObj)
    if maxLevel and heroObj:GetHeroLevel() >= maxLevel then
        return { state = -4, }
    end

    local classRef = LxDataHelper.GetHeroClassRefByHeroObj(heroObj)
    if not classRef then return {} end

    local lv = heroObj:GetHeroLevel()
    local classNeedLv = classRef.needLevel
    if classNeedLv > 0 and classNeedLv <= lv then
        if heroObj.star < classRef.needStar then
            --- 前往升星
            return {
                target = 2,
                state = -2,
                tabType = 2,
                btnName = I18nText(2511),
                msg = "",
                payItemList = {}
            }
        end
        local payItemList = self:GetHeroClassNeedItem(classRef)
        local isEnough = CtrlCenter.Item:CheckItemListEnough(payItemList,false)
        return {
            target = 2,
            btnName = I18nText(2413),
            tabType = 1,
            state = isEnough and 0 or -1,
            msg = "",
            payItemList = payItemList,
        }
    end
    if classNeedLv < 1 then
        local maxStar = self:GetHeroClassMaxStarLimit(heroObj)
        if maxStar and maxStar > 0 and heroObj.star < maxStar then
            --- 前往升星
            return {
                target = 2,
                state = -2,
                tabType = 2,
                btnName = I18nText(2511),
                msg = "",
                payItemList = {}
            }
        end
        local curStarMaxLv = LxDataHelper.GetHeroCurStarMaxLevelByHeroObj(heroObj)
        if heroObj.level >= curStarMaxLv then
            --- 前往升星
            return {
                target = 2,
                state = -2,
                tabType = 2,
                btnName = I18nText(2511),
                msg = "",
                payItemList = {}
            }
        end
    end

    local minHeroLevel = ModuleCenter.Hero:GetMinLevelByHighestPowerHeroList(self._highestPowerHeroNum)

    local upLv = 0
    local level = lv or 1
    local hasNum
    ---@type V_HeroLevelRef

    local canMaxUpLv = GameTable.CharacterConfigRef["heroUpLvlTime"]
    local payItemList = {}
    local isMaxLvDis = false
    local heroMaxLvDis
    local needList = {}
    local hasList = {}  --- 拥有的数量
    for i = 0, canMaxUpLv - 1 do
        local lvRef = GameTable.CharacterLevelRef[level + i]
        if lvRef and lvRef.need then
            local oneList
            local itemId
            local needNum
            local needTotalNum = 0
            local canNum = 0
            local remaining = 0

            for k, v in pairs(lvRef.need) do
                oneList = string.split(v, "=")
                itemId = tonumber(oneList[2])
                needNum = tonumber(oneList[3])
                if not hasList[itemId] then
                    hasNum = ModuleCenter.Item:GetItemCount(itemId)
                    hasList[itemId] = hasNum
                end
                if not needList[itemId] then
                    needList[itemId] = 0
                end
                remaining = hasList[itemId] - needList[itemId]
                needTotalNum = needTotalNum + 1
                if remaining >= needNum then
                    canNum = canNum + 1
                end
            end

            if canNum >= needTotalNum and not isMaxLvDis then
                upLv = upLv + 1
                for k, v in pairs(lvRef.need) do
                    oneList = string.split(v, "=")
                    itemId = tonumber(oneList[2])
                    needNum = tonumber(oneList[3])
                    needList[itemId] = needList[itemId] + needNum --- 加上一级的消耗
                end
            else
                break
            end
        else
            break
        end
    end
    --- 进阶限制
    if classRef.needLevel > 0 and lv + upLv > classRef.needLevel then
        upLv = upLv - (lv + upLv - classRef.needLevel)
    end
    --local canMaxUpLv = GameTable.CharacterConfigRef["heroUpLvlTime"]

    --local heroExpId = Item_Ids.HeroExp
    --local silverId = Item_Ids.Silver

    --local constNumMap = {}
    --local residueNumMap = {}
    --local payItems = {heroExpId,silverId}
    --local hasNum
    --for i,itemId in ipairs(payItems) do
    --    hasNum = ModuleCenter.Item:GetItemCount(itemId)
    --    residueNumMap[itemId] = hasNum
    --    constNumMap[itemId] = hasNum
    --end

    --local needExp,needGold,heroMaxLvDis
    --for i = 1, canMaxUpLv do
    --    lvRef = GameTable.CharacterLevelRef[level]
    --    if not lvRef then break end
    --    if level == classNeedLv then break end
    --
    --    heroMaxLvDis = lvRef.heroMaxLvDis
    --    if heroMaxLvDis and heroMaxLvDis > 0 then
    --        if heroMaxLvDis < minHeroLevel then
    --            isMaxLvDis = true
    --            break
    --        end
    --    end
    --
    --    needExp = lvRef.needExp or 0
    --    local curExp = residueNumMap[heroExpId] or 0
    --    if curExp < needExp then break end
    --
    --    needGold = lvRef.needGold or 0
    --    if residueNumMap[silverId] < needGold then break end
    --
    --    residueNumMap[heroExpId] = residueNumMap[heroExpId] - needExp
    --    residueNumMap[silverId] = residueNumMap[silverId] - needGold
    --
    --    upLv = upLv + 1
    --    level = level + 1
    --    if rpCheck then break end
    --end
    --
    --local payItemList = {}
    local noUpLv = upLv < 1
    if noUpLv then
        local lvRef = GameTable.CharacterLevelRef[level]
        if lvRef then
            for _, v in pairs(lvRef.need) do
                local oneList = string.split(v, "=")
                local itemId = tonumber(oneList[2])
                local needNum = tonumber(oneList[3])
                table.insert(payItemList,{
                    type = ThingType.Item,
                    refId = itemId,
                    num = needNum
                })
            end
        end
    else
        for i, v in pairs(needList) do
            table.insert(payItemList,{
                type = ThingType.Item,
                refId = i,
                num = v
            })
