    local isEnough = CtrlCenter.Item:CheckItemListEnough(payItemList,false)

    return {
        target = 1,
        tabType = 1,
        state = isEnough and 1 or -1,
        btnName = noUpLv and I18nText(2512) or string.replace(I18nText(2423),upLv),
        payItemList = payItemList,
        msg = "",
        bGray = noUpLv,
        upLv = upLv,
