end

---@param classRef V_HeroClassRef
---@return V_Item[]
function LxHeroCtrl:GetHeroClassNeedItem(classRef)
    if not self._parseHeroClassNeedItemMap then
        self._parseHeroClassNeedItemMap = {}
    end
    local needItems = self._parseHeroClassNeedItemMap[classRef.refId]
    if not needItems then
        needItems = LxDataHelper.ParseItemStrList(classRef.needItem)
        self._parseHeroClassNeedItemMap[classRef.refId] = needItems
    end
    return needItems
end

---@param heroObj LxHeroObj
---@return number
--- return -2 满级
--- return 0 道具不足
--- return 1 可以升级
function LxHeroCtrl:CheckHeroUpLvState(heroObj)
    local level = heroObj:GetHeroLevel()
    local ref = GameTable.CharacterLevelRef[level]
    if ref.needExp == -1 then
        return -2
    end
    --- 升级消耗道具（道具ID）
    local heroUpLvlItem = GameTable.CharacterConfigRef["heroUpLvlItem"]
    local hasNum = ModuleCenter.Item:GetItemCount(heroUpLvlItem)
    if ref.needExp > hasNum then
        return 0
    end
    return 1
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroPotencySkillList(heroObj)
    if not heroObj then return {} end

    local splitList = self:GetCareerClassSkillList(heroObj)
    if #splitList < 1 then return {} end

    --- 2023/12/12 修改：潜能取消
    local classSkillIdxMap = heroObj.classSkillIdxMap
    local grade = heroObj:GetHeroGrade()
    local needGrade,skillList,serverClass
    local list = {}
    for i,v in ipairs(splitList) do
        needGrade = v.needGrade
        skillList = v.skillList
        local isLock = needGrade > grade
        serverClass = classSkillIdxMap[needGrade] or 0
        local showSkillId = skillList[serverClass + 1]
        table.insert(list,{
            needGrade = needGrade,
            isLock = isLock,
            skillId = showSkillId
        })
    end
    return list
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetUpGradePotencySkillList(heroObj)
    if not heroObj then
        return {}
    end

    local splitList = self:GetCareerClassSkillList(heroObj)
    if #splitList < 1 then
        return {}
    end

    --- 2023/12/12 修改：潜能取消
    local grade = heroObj:GetHeroGrade()
    local classSkillIdxMap = heroObj.classSkillIdxMap or {}
    local recordIdx
    local sameGrade
    local curActGrade
    for i, v in ipairs(splitList) do
        if grade >= v.needGrade then
            recordIdx = i
        end
        if grade == v.needGrade then
            curActGrade = true
            sameGrade = grade
        end
    end
    if recordIdx then
        if not curActGrade then
            recordIdx = recordIdx + 1
            if recordIdx > #splitList then
                recordIdx = #splitList
            end
        end
    else
        recordIdx = 1
    end
    local isCur = sameGrade == grade
    local _splitList = splitList[recordIdx]
    local _needGrade = _splitList.needGrade
    local _skillList = _splitList.skillList
    local list = {}
    local isSel = false
    for i, v in ipairs(_skillList) do
        isSel = classSkillIdxMap[_needGrade] == i-1 and true or false
        table.insert(list, {
            needGrade = _needGrade,
            skillId = v,
            isCur = isCur,
            isSel = isSel
        })
    end

    local isNextGrade = grade + 1 == _needGrade
    return {
        skillList = list,
        needGrade = _needGrade,
        isNextGrade = isNextGrade,
        isCur = isCur
    }
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroStarSkillUnlockList(heroObj,skillId)
    local gradeSkillList = {}
    local recordSkillMap = {}
    local skillGroup = LxDataHelper.GetSkillGroup(skillId)
    local heroRefId = heroObj.refId
    local initStar = LxDataHelper.GetHeroInitStar(heroRefId)
    local maxStar = LxDataHelper.GetHeroMaxStarByRefId(heroRefId)
    local starId
    for i = initStar,maxStar do
        starId = LxDataHelper.GetHeroStarId(heroRefId,i)
        local skillInfo = self:GetHeroStarSkillListByStarId(starId)
        local skillGroupMap = skillInfo and skillInfo.skillGroupMap
        local data = skillGroupMap and skillGroupMap[skillGroup]
        if data and #data > 0 then
            for ii,v in ipairs(data) do
                if not recordSkillMap[v.skillId] then
                    table.insert(gradeSkillList,{
                        needGrade = v.needGrade,
                        skillId = v.skillId,
                    })
                    recordSkillMap[v.skillId] = true
                end
            end
        end
    end
    return gradeSkillList
end

function LxHeroCtrl:GetHeroStarSkillList(heroObj, type)
    local starId = LxDataHelper.GetHeroStarIdByHeroObj(heroObj)
    local skillInfo = self:GetHeroStarSkillListByStarId(starId, type)
    local list
    if type == HeroSkillGroupTypeEnums.Operate then
        list = skillInfo.skillBuildList
    elseif type == HeroSkillGroupTypeEnums.Strategy then
        list = skillInfo.skillArmyList
    elseif type == HeroSkillGroupTypeEnums.UpGrade then
        list = skillInfo.gradeSkillMap
    else
        list = skillInfo.skillGroupList
    end
    return list
end

function LxHeroCtrl:GetHeroStarSkillListByStarId(starId, type)
    return self:_GetParseHeroStarSkillList(starId, type)
end

function LxHeroCtrl:GetSuperHeroStarSkillList(heroObj)
    local list = {}
    local skillInfo = self:GetHeroStarSkillList(heroObj)
    local skillIdList = skillInfo.skillIdList
    for i,v in ipairs(skillIdList) do
        if not v.emptySkill then
            table.insert(list,{
                skillType = v.skillType,
                skillId = v.skillId,
                needGrade = v.needGrade,
                skillType1 = SkillType1Enums.Normal,
            })
        end
    end
    local superSkill = self:GetHeroBreakSkillByHeroObj(heroObj)
    local lockStr = ""
    local isUnlock = superSkill and superSkill > 0
    if not isUnlock then
        superSkill = self:GetHeroBreakSkillByHeroObj(heroObj,true)
    end
    if superSkill and superSkill > 0 then
        table.insert(list,{
            skillType = 1,
            skillId = superSkill,
            skillType1 = SkillType1Enums.SOUL,
            isUnlock = isUnlock,
            lockStr = lockStr,
        })
    end
    return list
end

---@type LxHeroSkillData[]
function LxHeroCtrl:DealSkillGroupList(skillGroupCnf, skillConfigType, heroSkillKeyList)
    local skillType, skillId, needGrade
    local skillCfg
    ---@type LxHeroSkillData[]
    local list = {}
    ---@type LxHeroSkillData
    local skillData
    if skillGroupCnf then
        for i2, v2 in ipairs(skillGroupCnf) do

            local skillList = string.split(v2, "|")
            for i, v in ipairs(skillList) do
                local data = string.split(v, "=")
                skillId = checknumber(data[1])
                needGrade = checknumber(data[2])
                skillType = 0
                skillCfg = GameTable.SnakeSkillRef[skillId]
                if skillCfg then
                    skillType = skillCfg.type == 2 and SkillTypeEnums.Passivity or skillCfg.type
                end
                skillData = require("LApp.module.hero.LxHeroSkillData"):new()
                skillData:SetData(skillId, needGrade, skillType, skillConfigType)
                table.insert(list, skillData)

                if heroSkillKeyList then
                    local gradeSkillList = heroSkillKeyList[needGrade]
                    if not gradeSkillList then
                        gradeSkillList = {}
                        heroSkillKeyList[needGrade] = gradeSkillList
                    end
                    table.insert(gradeSkillList, skillId)
                end
            end
        end
    end

    return list
end

