---@param skillRef V_SkillRef 技能 refId 转 技能效果 pasvEffect
function LxHeroCtrl:GetSR2SERPasvEffects(skillRef)
    if not self._parseSRSkillEffectMap then
        self._parseSRSkillEffectMap = {}
    end
    local refId = skillRef.refId
    local parseSkillEffects = self._parseSRSkillEffectMap[refId]
    if not parseSkillEffects then
        parseSkillEffects = {}
        local skillEffect = skillRef.skillEffect
        local needSplit = string.split(skillEffect, "=")
        if needSplit and #needSplit > 2 then
            local str = needSplit[3]
            str = string.gsub(str, "{", "")
            str = string.gsub(str, "}", "")
            str = string.split(str, ",")
            for _i, _v in ipairs(str) do
                _v = string.split(_v,"|")
                for idx,val in ipairs(_v) do
                    table.insert(parseSkillEffects, checknumber(val))
                end
            end
        else
            skillEffect = string.split(skillEffect, "|")
            for _i, _v in ipairs(skillEffect) do
                table.insert(parseSkillEffects, checknumber(_v))
            end
        end
        self._parseSRSkillEffectMap[refId] = parseSkillEffects
    end
    return parseSkillEffects
end

---@param skillEffectRef V_SkillEffectRef
---@return V_Attr[]
function LxHeroCtrl:GetPasvEffectBySkillEffectRef(skillEffectRef)
    if not self._parseSERPasvEffectMap then
        self._parseSERPasvEffectMap = {}
    end
    local refId = skillEffectRef.refId
    local parseSERPasvEffects = self._parseSERPasvEffectMap[refId]
    if not parseSERPasvEffects then
        parseSERPasvEffects = {}
        local pasvEffect = skillEffectRef.pasvEffect
        if pasvEffect and #pasvEffect > 0 then
            parseSERPasvEffects = LxDataHelper.ParseAttrStr(pasvEffect, ",")
        end
        self._parseSERPasvEffectMap[refId] = parseSERPasvEffects
    end
    return parseSERPasvEffects
end

---@param heroObj LxHeroObj
