---@param heroObj LxHeroObj
function LxHeroCtrl:GetUpGradeAttrListByHeroObj(heroObj,oldGrade)
    local star = heroObj.star
    local refId = heroObj.refId
    local level = heroObj.level
    local grade = oldGrade or heroObj:GetHeroGrade()
    local nextGrade = grade + 1
    local oGradeAttrMap = self:CalcHeroAttrList(refId,star,grade,level)
    local nGradeAttrMap = self:CalcHeroAttrList(refId,star,nextGrade,level)
    local list = {}
    local bValue
    local attrRefList = GameTable.CombatAttributeRef
    for k,v in pairs(nGradeAttrMap) do
        local ref =attrRefList[k]
        if ref.type == AttrType.Base and ref.refId < 20 then    --- 只显示一部分基础属性
            bValue = oGradeAttrMap[k] or 0
            table.insert(list,{
                refId = k,
                bValue = bValue.value,
                nValue = math.floor(v.value + 0.5),
            })
        end

    end
    table.sort(list,function(a,b)
        return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
    end)
    return list
end

--- 计算属性
function LxHeroCtrl:CalcHeroAttrList(refId,star,grade,lv)
    local attrMap = {}
    local mode = ModuleCenter.Hero:GetCurMode()
    local starId = LxDataHelper.GetHeroStarId(refId,star)
    local skillPasvAttrMap = self:GetSkillPasvAttrList(starId,grade)

    local heroRef = LxDataHelper.GetHeroRef(refId)
    ---@type table<number,V_Attr> 英雄属性 初始值
    local initAttributeMap = self:GetHeroInitAttributeMap(heroRef)

    ---@type table<number,V_Attr> 英雄属性 成长系数
    local levelAttributeMap = self:GetHeroLevelAttributeMap(heroRef)

    local classType = LxDataHelper.GetHeroClassTypeByHeroRefId(refId)
    local classId = LxDataHelper.GetClassId(classType,grade)
    local classRef = LxDataHelper.GetHeroClassRefByClassId(classId)
    ---@type table<number,V_Attr> 阶级系数
    local attrValueMap = self:GetHeroClassAttrValueMap(classRef)

    ---@type table<number,V_Attr> 阶级固定值
    local attrValueExMap = self:GetHeroClassAttrValueExMap(classRef)

    local starRef = LxDataHelper.GetHeroStarRef(starId)
    ---@type table<number,V_Attr> 星级系数
    local starAttrMap = self:GetParseHeroStarAttrUpValMap(starRef)

    ---@type table<number,V_Attr> 星级固定值
    local starAttrExMap = self:GetParseHeroStarAttrUpVal1Map(starRef)



    --- 无规定属性列表参考，收集所有属性
    local collectAttrMap = {}
    self:_CollectAttrMap(skillPasvAttrMap,collectAttrMap)
    self:_CollectAttrMap(initAttributeMap,collectAttrMap)
    self:_CollectAttrMap(levelAttributeMap,collectAttrMap)
    self:_CollectAttrMap(attrValueMap,collectAttrMap)
    self:_CollectAttrMap(attrValueExMap,collectAttrMap)
    self:_CollectAttrMap(starAttrMap,collectAttrMap)
    self:_CollectAttrMap(starAttrExMap,collectAttrMap)

    ---蛇模式 (初始值 + 等级 * 成长系数 * 阶级系数 * 星级系数) * (1 + 被动技能增幅百分比系数累和) + 被动技能固定值加成累和 + 阶级固定值 + 星级固定值
    --- 竞品模式 英雄属性=（初始属性+等级*等级成长属性*阶级属性成长*升星属性成长+各个模块A类固定值累和（这个值客户端不需要计算））*（1+被动技能增幅系数累和）+被动技能固定值B类加成累和（这个值客户端不需要计算）+阶级额外成长B类+升星额外成长B类
    local baseVal,levelVal,cAttrValEx,sAttrEx,skillAttrFixVal,skillAttrPercentVal,classAttrFixVal,starAttrFixVal
    local baseAttrVal,skillPercentNum
    local tempResVal
    for attrRefId,v in pairs(collectAttrMap) do
        baseVal = initAttributeMap[attrRefId] and initAttributeMap[attrRefId].value or 0
        levelVal = levelAttributeMap[attrRefId] and levelAttributeMap[attrRefId].value or 0
        cAttrValEx = mode == HeroModeType.Snake and (attrValueMap[attrRefId] and attrValueMap[attrRefId].value or 0) or 1
        sAttrEx = starAttrMap[attrRefId] and starAttrMap[attrRefId].value or 0
        skillAttrFixVal = (skillPasvAttrMap[attrRefId] and skillPasvAttrMap[attrRefId].refIdMap[1]) and skillPasvAttrMap[attrRefId].refIdMap[1] or 0
        skillAttrPercentVal = (skillPasvAttrMap[attrRefId] and skillPasvAttrMap[attrRefId].refIdMap[2]) and skillPasvAttrMap[attrRefId].refIdMap[2] or 0
        starAttrFixVal = starAttrExMap[attrRefId] and starAttrExMap[attrRefId].value or 0
        classAttrFixVal = mode == HeroModeType.Snake and (attrValueExMap[attrRefId] and attrValueExMap[attrRefId].value or 0) or 0
        baseAttrVal = baseVal + lv * levelVal * cAttrValEx * sAttrEx
        skillPercentNum = 1 + skillAttrPercentVal
        tempResVal = baseAttrVal * skillPercentNum + skillAttrFixVal + classAttrFixVal + starAttrFixVal
        attrMap[attrRefId] = {refId = attrRefId, value = tempResVal, tar = 0}
    end
    local attrRefList = GameTable.CombatAttributeRef
    -- 士兵属性 直接覆盖
    local armyList = LxDataHelper.ParseAttrStr(starRef.armyAttrUpVal)
    for i, v in ipairs(armyList) do
        --if attrRefList[v.refId].isShow > 0 then
            attrMap[v.refId] = v
        --end
    end

    -- 初始命中率 写死
    local initHit = GameTable.CharacterConfigRef.heroInitHit
    attrMap[103] = {refId = 103, value = initHit, tar = 0}
    -- 初始爆伤 写死
    local initCrit= GameTable.CharacterConfigRef.heroInitCritRatio
    attrMap[203] = {refId = 203, value = initCrit, tar = 0}

    -- 带兵数量
    local lvRef = GameTable.CharacterLevelRef[lv]
    local attrList = LxDataHelper.ParseAttrList(lvRef.armyAttr)
    for i, v in ipairs(attrList) do
        if attrRefList[v.refId].isShow > 0 then
            attrMap[v.refId] = v
        end
    end
    local tarList = self:GetHeroSlgSkillAttr(attrMap, starId)
    --- 合并B类属性到A类里面去 这属性乱的一批
    if mode == HeroModeType.Compete then
        local b_baseAttr = {[21] = true, [22] = true, [23] = true, [24] = true}
        for i, v in pairs(attrMap) do
            if b_baseAttr[v.refId] then
                local showAttrId = 10 + (v.refId % 10)
                if attrMap[showAttrId] then
                    attrMap[showAttrId].value = attrMap[showAttrId].value + v.value
                end
            end
        end

        for k, v in pairs(b_baseAttr) do
            attrMap[k] = nil
        end
    end
    return attrMap, tarList
end

---@param attrMap table<number,V_Attr>
function LxHeroCtrl:_CollectAttrMap(attrMap,collectMap)
    for k,v in pairs(attrMap) do
        if not collectMap[v.refId] then
            collectMap[v.refId] = true
        end
    end
end

---@param grade number 被动技能增加的属性
function LxHeroCtrl:GetSkillPasvAttrList(starId,grade)
    local skillInfo = self:_GetParseHeroStarSkillList(starId)
    if not skillInfo then return {} end

    local skillIds = {}
    for i,v in ipairs(skillInfo.skillGroupList) do
        if grade >= v.needGrade and v.skillType == SkillTypeEnums.Passivity then
            table.insert(skillIds,v)
        end
    end
    if #skillIds < 1 then return {} end
    local attrRefId
    local attrMap = {}
    local skillRef,skillEffectRef,pasvEffectAttrs,numShowType
    for i,v in ipairs(skillIds) do
        skillRef = LxDataHelper.GetSkillRef(v.skillId)
        if skillRef then
            local skillEffectIds = self:GetSR2SERPasvEffects(skillRef)
            for idx, skillEffectId in ipairs(skillEffectIds) do
                skillEffectRef = LxDataHelper.GetSkillEffectRef(skillEffectId)
                if skillEffectRef then
                    ---@type V_Attr[]
                    pasvEffectAttrs = self:GetPasvEffectBySkillEffectRef(skillEffectRef)
                    if #pasvEffectAttrs > 0 then
                        for _i,attr in ipairs(pasvEffectAttrs) do
                            attrRefId = attr.refId
                            local showRefId = attr.refId
                            if attr.refId < 100 then    --- 显示的基础属性类型
                                showRefId = 10 + (attr.refId % 10)
                            end
                            local refIdMap = attrMap[showRefId]
                            if not refIdMap then
                                refIdMap = {}

                                attrMap[showRefId] = {refId = showRefId, refIdMap = refIdMap , tar = 0}
                            else
                                refIdMap = attrMap[showRefId].refIdMap
                            end
                            numShowType = LxDataHelper.GetCombatAttributeRefNumShowType(attrRefId)
                            local numShowTypeNum = refIdMap[numShowType] or 0
                            refIdMap[numShowType] = numShowTypeNum + attr.value
                        end
                    end
                end
            end
        end
    end

    return attrMap
end

---@param attrList table<V_Attr> list 2 map
function LxHeroCtrl:AttrList2AttrMap(attrList)
    local attrMap = {}
    for i,v in ipairs(attrList) do
        attrMap[v.refId] = v
    end
    return attrMap
end

