function LxHeroCtrl:GetHeroAttrList(heroObj)
    local attrList = heroObj:GetAttrList()
    local starId = LxDataHelper.GetHeroStarIdByHeroObj(heroObj)
    local starRef = LxDataHelper.GetHeroStarRef(starId)
    local attrRefList = GameTable.CombatAttributeRef
    local slgSkillRefList = GameTable.SlgSkillRef
    local _tAttr = {}   -- 以属性id作为key
    local showList = {}
    for i, v in ipairs(attrList) do
        _tAttr[v.refId] = v
        --table.insert(showList, v)
    end
    local armyList = LxDataHelper.ParseAttrStr(starRef.armyAttrUpVal)
    for i, v in ipairs(armyList) do
        --if attrRefList[v.refId].isShow > 0 then
        --    table.insert(showList, v)
        --end
        local _t = _tAttr[v.refId]
        if not _t or _t.tar ~= v.tar then
            _tAttr[v.refId] = v
        else
            _t.value = _t.value + v.value
        end

    end
    -- 带兵数量
    local lvRef = GameTable.CharacterLevelRef[heroObj.level]
    local armyAttrList = LxDataHelper.ParseAttrList(lvRef.armyAttr)
    for i, v in ipairs(armyAttrList) do
        if attrRefList[v.refId].isShow > 0 then
            --table.insert(showList, v)
            local _t = _tAttr[v.refId]
            if not _t or _t.tar ~= v.tar then
                _tAttr[v.refId] = v
            else
                _t.value = _t.value + v.value
            end
        end
    end

    --- 加上slg技能提供的属性
    local tarList = self:GetHeroSlgSkillAttr(_tAttr, starId)
    for i, v in pairs(_tAttr) do
        table.insert(showList, v)
    end
    for i, v in ipairs(tarList) do
        table.insert(showList, v)
    end
    return showList
end

function LxHeroCtrl:GetHeroSlgSkillAttr(attrList, starId)
    local slgSkillRefList = GameTable.SlgSkillRef
    local skillList = self:_GetParseHeroStarSkillList(starId)
    local tarList = {} --- 同一个属性id 但是 作用对象类型 不一样的
    -- 策略技能
    for _, v in ipairs(skillList.skillArmyList) do
        local ref = slgSkillRefList[v.skillId]
        if ref and (ref.conditions == 2 and ref.type == 1) then
            local strategyList = LxDataHelper.ParseAttrList(ref.effect)
            for i2, v2 in ipairs(strategyList) do
                local _t = attrList[v2.refId]
                if not _t then
                    attrList[v2.refId] = v2
                elseif _t.tar ~= v2.tar then
                    table.insert(tarList, v2)
                else
                    _t.value = _t.value + v2.value
                end
            end
        end
    end
    -- 经营技能
    for _, v in ipairs(skillList.skillBuildList) do
        local ref = slgSkillRefList[v.skillId]
        if ref and (ref.conditions == 2 and ref.type == 1) then
            local operateList = LxDataHelper.ParseAttrList(ref.effect)
            for i2, v2 in ipairs(operateList) do
                local _t = attrList[v2.refId]
                if not _t then
                    attrList[v2.refId] = v2
                elseif _t.tar ~= v2.tar then
                    table.insert(tarList, v2)
                else
                    _t.value = _t.value + v2.value
                end
            end
        end
    end
    return tarList
end

function LxHeroCtrl:UnBattleHero(battleType,unBattleHeroMap)
    ---@type LxFormationObj
    --local formationGroup = ModuleCenter.Battle:GetFormationList(battleType)
    local formationGroup = ModuleCenter.Battle:GetFormationGroup(battleType)
    if not formationGroup then return end
    local positionList = {}
    for k,formation in pairs(formationGroup) do
        for pos, unitPosObj in pairs(formation.positions) do
            if not unBattleHeroMap[unitPosObj.id] then
                table.insert(positionList,unitPosObj)
            end
        end
    end
    local newFormation = ModuleCenter.Battle:NewFormation()
    local newFormationGroup = {
        order = formationGroup[1].order,
        power = formationGroup[1].power,
        positions = positionList,
        count = formationGroup[1].count
    }
    newFormation:SetPbData(newFormationGroup)
    HandlerCenter.Battle:SetFormationReq(battleType, {newFormation})
end

