---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroRefNextClassSkillId(heroObj)
    local classSkill = self:GetHeroRefClassSkill(heroObj.refId)
    if not classSkill then return end
    local nextGrade = heroObj:GetHeroGrade() + 1
    if nextGrade > #classSkill then
        nextGrade = #classSkill
    end
    return classSkill[nextGrade] and classSkill[nextGrade].skillId
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroClassAddsAttrList(heroObj)
    local grade = heroObj:GetHeroGrade()
    local classAddAttributes = self._rClassAddAttributesMap[grade]
    if not classAddAttributes then
        local attrMap = {}
        local attrTarMap = {}
        ---@type V_Attr
        local data
        local ref,attribute,attrRefId,attrValueB
        if grade == 0 then
            ref = GameTable.CharacterClassRef[1]
            attribute = ref and ref.attribute
            if attribute and #attribute > 0 then
                for idx,val in ipairs(attribute) do
                    data = LxDataHelper.ParseAttrItem(val)
                    attrRefId = data.refId
                    attrMap[attrRefId] = 0
                    if not attrTarMap[attrRefId] then
                        attrTarMap[attrRefId] = data.tar
                    end
                end
            end
        else
            for i = 1,grade do
                ref = GameTable.CharacterClassRef[i]
                attribute = ref and ref.attribute
                if attribute and #attribute > 0 then
                    for idx,val in ipairs(attribute) do
                        data = LxDataHelper.ParseAttrItem(val)
                        attrRefId = data.refId
                        attrValueB = attrMap[attrRefId] or 0
                        attrMap[attrRefId] = attrValueB + data.value
                        if not attrTarMap[attrRefId] then
                            attrTarMap[attrRefId] = data.tar
                        end
                    end
                end
            end
        end
        classAddAttributes = {}
        for k,v in pairs(attrMap) do
            table.insert(classAddAttributes,{
                refId = k,
                value = v,
                tar = attrTarMap[k],
            })
        end
        table.sort(classAddAttributes,function(a,b)
            return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
        end)
        self._rClassAddAttributesMap[grade] = classAddAttributes
    end
    return classAddAttributes
end

function LxHeroCtrl:GetHeroShareInfo()
    --- 共享等级,共享阶级
    local shareLevel,shareGrade
    local heroList = ModuleCenter.Hero:GetHeroList()
    for k,v in pairs(heroList) do
        if shareLevel and shareGrade then break end
        if not shareLevel and v.shareLevel > 0 then
            shareLevel = v.shareLevel
        end
        if not shareGrade and v.shareGrade > 0 then
            shareGrade = v.shareGrade
        end
    end
    if not shareLevel then shareLevel = 1 end
    if not shareGrade then shareGrade = 0 end
    return shareLevel,shareGrade
end

---- 获取英雄初始化 可见属性和总属性(用于计算战力)
function LxHeroCtrl:GetInitHeroAttributeList(refId,showLevel,showGrade)
    if not showLevel then return {} end

    if not showGrade then return {} end

    local heroRef = GameTable.CharacterRef[refId]
    if not heroRef then return {} end
    local attrMap = {}
    local attrRefId,attrValue
    local initAttribute = heroRef.initAttribute
    ---@type V_Attr[]
    local initAttributeList
    if initAttribute and #initAttribute > 0 then
        --- HeroRef 的 initAttribute
        initAttributeList = LxDataHelper.ParseAttrList(initAttribute)
        for i,v in ipairs(initAttributeList) do
            attrRefId = v.refId
            attrValue = attrMap[attrRefId] or 0
            attrMap[attrRefId] = attrValue + v.value
        end
    end
    local levelAttribute = heroRef.levelAttribute
    if levelAttribute and #levelAttribute > 0 then
        --- HeroRef 的 levelAttribute
        initAttributeList = LxDataHelper.ParseAttrList(levelAttribute)
        for i,v in ipairs(initAttributeList) do
            attrRefId = v.refId
            attrValue = attrMap[attrRefId] or 0
            attrMap[attrRefId] = attrValue + v.value
        end
    end

    --[[local quality = heroRef.quality
    local careerType = LxDataHelper.GetHeroCareerType(refId)
    local attributeType = heroRef.attributeType
    for k,v in pairs(GameTable.HeroAttributeRef) do
        if v.attributeType == attributeType and v.careerType == careerType and v.quality == quality then
            initAttribute = v.initAttribute
            if initAttribute and #initAttribute > 0 then
                --- HeroAttributeRef 的 initAttribute
                initAttributeList = LxDataHelper.ParseAttrList(initAttribute)
                for idx,val in ipairs(initAttributeList) do
                    attrRefId = val.refId
                    attrValue = attrMap[attrRefId] or 0
                    attrMap[attrRefId] = attrValue + val.value
                end
            end

            levelAttribute = v.levelAttribute
            if levelAttribute and #levelAttribute > 0 then
                --- HeroAttributeRef levelAttribute * 等级
                initAttributeList = LxDataHelper.ParseAttrList(levelAttribute)
                for idx,val in ipairs(initAttributeList) do
                    attrRefId = val.refId
                    attrValue = attrMap[attrRefId] or 0
                    attrMap[attrRefId] = attrValue + val.value * showLevel
                end
            end
        end
    end]]

    if showGrade and showGrade > 0 then
        local gradeRef = GameTable.CharacterClassRef[showGrade]
        local attribute = gradeRef and gradeRef.attribute
        if attribute and #attribute > 0 then
            --- HeroClassRef attribute
            initAttributeList = LxDataHelper.ParseAttrList(attribute)
            for idx,val in ipairs(initAttributeList) do
                attrRefId = val.refId
                attrValue = attrMap[attrRefId] or 0
                attrMap[attrRefId] = attrValue + val.value * showLevel
            end
        end
    end


    local changeAttrMap = {}
    local realAttrRefId,realAttrVal
    for k,v in pairs(attrMap) do
        realAttrRefId = self:GetRealAttrRefId(k)
        realAttrVal = changeAttrMap[realAttrRefId] or 0
        changeAttrMap[realAttrRefId] = realAttrVal + v
    end

    local showAttrList = {}
    local list = {}
    for k,v in pairs(changeAttrMap) do
        local data = {
            refId = k,
            value = v,
        }
        if LxDataHelper.GetCombatAttributeIsShow(k) then
            table.insert(showAttrList,data)
        end
        table.insert(list,data)
    end
    table.sort(showAttrList,function(a,b)
        return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
    end)

    local attrInfos = {
        showAttrList = showAttrList,
        allAttrList = list,
        attrMap = attrMap,
        changeAttrMap = changeAttrMap,
    }
    return attrInfos
end

