--- 获取英雄等级战力
---@field refId @英雄refId
---@field showLevel @等级
function LxHeroCtrl:GetInitHeroPower(refId,showLevel,showGrade)
    if not refId then return 0 end
    if not showLevel then return 0 end
    if not showGrade then return 0 end

    local attrInfos = self:GetInitHeroAttributeList(refId,showLevel,showGrade)
    local showAttrList = attrInfos.showAttrList or {}
    if #showAttrList < 1 then return 0 end

    --- attrRefId 2 coefficient
    local coefficientMap = self:GetRoleLevelAttrMap(showLevel)
    local power = 0
    local coefficient
    local changeAttrMap = attrInfos.changeAttrMap
    for k,v in pairs(changeAttrMap) do
        coefficient = coefficientMap[k] or 1
        power = power + v * coefficient
    end

    local deductPower = 0
    local deductAttrMap = self._initDeductAttrMap
    for k,v in pairs(deductAttrMap) do
        coefficient = coefficientMap[k] or 1
        deductPower = deductPower + v * coefficient
    end

    return power - deductPower
end

function LxHeroCtrl:GetRealAttrRefId(attrRefId)
    if attrRefId >= 100 or attrRefId < 10 then return attrRefId end
    if attrRefId / 10 == 0 then return attrRefId end
    local realAttrRefId = attrRefId % 10
    local ref = GameTable.CombatAttributeRef[realAttrRefId]
    if not ref then
        realAttrRefId = attrRefId
    end
    return realAttrRefId
end

function LxHeroCtrl:OpenUpInfo(oldPower,newPower,oldAttrList,newAttrList,optEnum)
    oldPower = checknumber(oldPower)
    newPower = checknumber(newPower)
    local showInfoNum = 0
    local data = {}
    if oldPower and newPower and newPower ~= oldPower then
        data.oldPower = oldPower
        data.newPower = newPower
        showInfoNum = showInfoNum + 1
    end
    if optEnum == 1 then
        oldAttrList = oldAttrList or {}
        newAttrList = newAttrList or {}
        if #oldAttrList > 0 or #newAttrList > 0 then
            data.old = oldAttrList
            data.new = newAttrList
            showInfoNum = showInfoNum + 1
        end
    end
    if showInfoNum < 1 then return end

    local oldRolePower, newRolePower = CtrlCenter.Role:GetRolePowerChange()
    data.oldRolePower = oldRolePower
    data.newRolePower = newRolePower

    local uiKey = UiNames.FloatUpInfo
    --if IsOpenPanel(uiKey) then
    --    RefreshPanel(uiKey, data)
    --else
        ShowPanel(uiKey, data)
    --end
end

