---@param heroObj LxHeroObj
function LxHeroCtrl:PrintHeroObjAttrMap(heroObj,format)
    if not LOG_INFO_ENABLED then return end

    local attrStrs = {}
    for k,v in pairs(heroObj.attrMap) do
        local str = LxDataHelper.GetCombatAttributeName(v.refId) .. ":" .. v.value
        if LxDataHelper.GetCombatAttributeIsShow(k) then
            str = str .. "(显示)"
        end
        table.insert(attrStrs,str)
    end
    if format then
        printInfo("打印：》》",format .. ",属性数据：%s",table.concat(attrStrs,","))
    else
        printInfo("打印：》》","属性数据：%s",table.concat(attrStrs,","))
    end
end

