    --阶级refId拼接:英雄classType+1位阶级数字
    local heroInfo = ModuleCenter.Hero:GetHero(heroId)
    if not heroInfo then return end
    local heroRefId = heroInfo.refId
    local classType = GameTable.CharacterRef[heroRefId].classType
    grade = grade or heroInfo:GetHeroGrade()
    local gradeReId = classType..grade
    return GameTable.CharacterClassRef[tonumber(gradeReId)]
end

