---@param heroStarRef V_HeroStarRef
function LxHeroCtrl:GetParseUpStarPayItemList(heroStarRef)
    if not self._paramsUpStarPayItemList then
        self._paramsUpStarPayItemList = {}
    end
    local payItemList = self._paramsUpStarPayItemList[heroStarRef.refId]
    if ModuleCenter.Debug.isTest then
        payItemList = nil
    end
    if not payItemList then
        local upStarAppointValid
        local upStarRangeValid
        local upStarItemValid
        local upStarAppoints = {}
        local oneList
        local quality = heroStarRef.quality
        local upStarAppointCnf = heroStarRef.upStarAppoint
        if not table.isempty(upStarAppointCnf) then
            upStarAppointValid = true
            for i, v in ipairs(upStarAppointCnf) do
                oneList = string.split(v, "=")
                table.insert(upStarAppoints, {
                    heroRefId = checknumber(oneList[1]),
                    star = checknumber(oneList[2]),
                    payNum = checknumber(oneList[3]),
                    payType = HeroUpStarEnums.Appoint_Hero,
                    idx = i,
                    quality = quality,
                })
            end
        end

        local upStarRanges = {}
        local upStarRangeCnf = heroStarRef.upStarRange
        if not table.isempty(upStarRangeCnf) then
            upStarRangeValid = true
            for i, v in ipairs(upStarRangeCnf) do
                oneList = string.split(v, "=")
                table.insert(upStarRanges, {
                    heroRaceType = checknumber(oneList[1]),
                    star = checknumber(oneList[2]),
                    payNum = checknumber(oneList[3]),
                    payType = HeroUpStarEnums.Range_Hero,
                    idx = i,
                    quality = quality,
                })
            end
        end

        local upStarItems = {}
        local upStarItemCnf = heroStarRef.upStarItem
        if not table.isempty(upStarItemCnf) then
            upStarItemValid = true
            for i, v in ipairs(upStarItemCnf) do
                oneList = string.split(v, "=")
                table.insert(upStarItems, {
                    type = checknumber(oneList[1]),
                    refId = checknumber(oneList[2]),
                    payNum = checknumber(oneList[3]),
                    num = checknumber(oneList[3]),
                    payType = HeroUpStarEnums.Appoint_Item,
                    idx = i,
                    quality = quality,
                })
            end
        end
        payItemList = {
            upStarAppoint = {
                list = upStarAppoints,
                isValid = upStarAppointValid,
            },
            upStarRange = {
                list = upStarRanges,
                isValid = upStarRangeValid,
            },
            upStarItem = {
                list = upStarItems,
                isValid = upStarItemValid,
            }
        }

        self._paramsUpStarPayItemList[heroStarRef.refId] = payItemList
    end
    return payItemList
end

