--- 获取遣返的英雄列表
function LxHeroCtrl:GetSacrificeHeroList(maskData)
    maskData = maskData or {}
    local raceType = maskData.raceType or 0
    local careerType = maskData.careerType or 0
    local attackType = maskData.attackType or 0

    local isIns
    local list = {}
    ---@type V_HeroStarRef
    local starRef
    ---@type table<string, LxHeroObj>
    local heroList = ModuleCenter.Hero:GetHeroList()
    for k,v in pairs(heroList) do
        starRef = LxDataHelper.GetHeroStarRefByHeroObj(v)
        if starRef and starRef.sacrificeGetItem and #starRef.sacrificeGetItem > 0 then
            isIns = raceType == 0 or raceType == LxDataHelper.GetHeroRaceTypeByHeroObj(v)
            if isIns then
                isIns = careerType == 0 or careerType == LxDataHelper.GetHeroCareerTypeByHeroObj(v)

                if isIns then
                    isIns = attackType == 0 or attackType == LxDataHelper.GetHeroActType(v.refId)
                end
            end
            if isIns then
                table.insert(list,{
                    heroObj = v,
                    sacrificeGetItems = self:GetHeroStarSacrificeGetItem(starRef),
                })
            end
        end
    end

    local formationData = ModuleCenter.Battle:GetFormation(BattleType.Adventure)    -- 阵容信息
    local pos = {}
    if not table.isempty(formationData) then
        for _, v in pairs(formationData.positions) do
            pos[v.id] = 1
        end
    end
    local heroRef = GameTable.CharacterRef
    --- 遣返排序 初始品质顺序-> 已锁定 -> 出战中->英雄唯一id
    table.sort(list,function(a,b)
        local aInfo = a.heroObj
        local bInfo = b.heroObj
        local aRef = heroRef[aInfo.refId]
        local bRef = heroRef[bInfo.refId]

        -- 出战中
        local aPosV = pos[aInfo.id] and 100000 or 0
        local bPosV = pos[bInfo.id] and 100000 or 0
        -- 是否锁定
        local aLockV = aInfo.lock and 10000 or 0
        local bLockV = bInfo.lock and 10000 or 0

        -- 初始品质
        local aSort = aRef.quality + aLockV + aPosV
        local bSort = bRef.quality + bLockV + bPosV

        if aSort ~= bSort then
            return aSort < bSort
        else
            return checknumber(aInfo.id) < checknumber(bInfo.id)
        end
    end)
    return list
end

--- 获取转生的英雄列表
function LxHeroCtrl:GetRebirthHeroList(maskData, star)
    maskData = maskData or {}
    local raceType = maskData.raceType or 0
    local careerType = maskData.careerType or 0
    local attackType = maskData.attackType or 0

    --- >=6星的英雄才可转生
    local heroReturnStar = GameTable.CharacterConfigRef["heroReturnStar"]

    if star then
        heroReturnStar = star
    end

    local isIns
    local list = {}
    ---@type table<string, LxHeroObj>
    local heroList = ModuleCenter.Hero:GetHeroList()
    for k,v in pairs(heroList) do
        if not LxDataHelper:CheckIsSuperHero(v) then
            if v.star >= heroReturnStar then
                isIns = raceType == 0 or raceType == LxDataHelper.GetHeroRaceTypeByHeroObj(v)
                if isIns then
                    isIns = careerType == 0 or careerType == LxDataHelper.GetHeroCareerTypeByHeroObj(v)

                    if isIns then
                        isIns = attackType == 0 or attackType == LxDataHelper.GetHeroActType(v.refId)
                    end
                end
                if isIns then
                    table.insert(list,{
                        heroObj = v,
                    })
                end
            end
        end
    end
    table.sort(list,function(a,b)
        ---@type LxHeroObj
        local heroObjA = a.heroObj
        ---@type LxHeroObj
        local heroObjB = b.heroObj
        if heroObjA.star ~= heroObjB.star then return heroObjA.star < heroObjB.star end
        local initStarA = LxDataHelper.GetHeroInitStar(heroObjA.refId)
        local initStarB = LxDataHelper.GetHeroInitStar(heroObjB.refId)
        if initStarA ~= initStarB then return initStarA < initStarB end
        if heroObjA.level ~= heroObjB.level then return heroObjA.level < heroObjB.level end
        return heroObjA.refId < heroObjB.refId
    end)
    return list
end

--- 获取批量升星的英雄列表
function LxHeroCtrl:GetBatchUpStarHeroList(maskData)
    maskData = maskData or {}
    local raceType = maskData.raceType or 0
    local careerType = maskData.careerType or 0
    local attackType = maskData.attackType or 0

    local list = {}
    local isIns = false
    local upStar
    local refId
    ---@type table<string, LxHeroObj>
    local heroList = ModuleCenter.Hero:GetHeroList()
    for k,v in pairs(heroList) do
        if not LxDataHelper.CheckHeroIsMaxStar(v) then
            refId = v.refId
            isIns = false
            if raceType == 0 or raceType == LxDataHelper.GetHeroRaceType(refId) then
                if careerType == 0 or careerType == LxDataHelper.GetHeroCareerType(refId) then
                    if attackType == 0 or attackType == LxDataHelper.GetHeroActType(refId) then
                        isIns = true
                    end
                end
            end
            if isIns then
                ---@type V_HeroStarRef
                local starRef = LxDataHelper.GetHeroStarRefByHeroObj(v)
                upStar = starRef and starRef.upStar
                if upStar and upStar == 1 then
                    table.insert(list,{
                        heroObj = v,
                        starRef = starRef,
                        isCanUpStar = self:CheckHeroIsCanUpStar(v),
                    })
                end
            end
        end
    end
    table.sort(list,function(a,b)
        local upStarA,upStarB = a.isCanUpStar and 1 or 0,b.isCanUpStar and 1 or 0
        if upStarA ~= upStarB then return upStarA > upStarB end

        ---@type LxHeroObj
        local heroA = a.heroObj
        ---@type LxHeroObj
        local heroB = b.heroObj
        if heroA.level ~= heroB.level then return heroA.level > heroB.level end

        if heroA.refId ~= heroB.refId then return heroA.refId < heroB.refId end

        if heroA.power ~= heroB.power then return heroA.power > heroB.power end

        return heroA.id > heroB.id
    end)
    return list
end

---@param heroObj LxHeroObj 超凡英雄
---@param targetObj LxHeroObj 目标英雄
function LxHeroCtrl:GetComparisonSuperHeroAttrList(heroObj,targetObj)
    local refId = heroObj.refId
    local beforeAttrMap = self:CalcHeroAttrList(refId,heroObj.star,heroObj.grade,heroObj.level)
    local laterAttrMap = self:CalcHeroAttrList(refId,targetObj.star,targetObj.grade,targetObj.level)
    local list = {}
    local bValue,nValue
    for k,v in pairs(laterAttrMap) do
        if beforeAttrMap[k] then
            bValue = math.floor(beforeAttrMap[k].value + 0.5)
        else
            bValue = 0
        end
        nValue = math.floor(v.value + 0.5)
        table.insert(list,{
            refId = k,
            bValue = bValue,
            nValue = nValue,
        })
    end
    table.sort(list,function(a,b)
        return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
    end)
    return list
end

---@param heroObj LxHeroObj 目标英雄
function LxHeroCtrl:GetCanSelLinkHeroList(heroObj)
    if not heroObj then return {} end
    local initStar = LxDataHelper.GetHeroInitStar(heroObj.refId)
    ---@type table<string,LxHeroObj> 被链接的英雄
    local bLinkHeroMap = {}
    ---@type LxHeroObj
    local bLinkHeroObj
    local heroModule = ModuleCenter.Hero
    local link
    local heroList = heroModule:GetHeroList()
    for k,v in pairs(heroList) do
        link = v.link
        if string.isvalid(link) and link ~= "0" then
            bLinkHeroObj = heroModule:GetHero(link)
            if bLinkHeroObj then
                bLinkHeroMap[bLinkHeroObj.id] = bLinkHeroObj
            end
        end
    end
    ---@type LxHeroObj[]
    local canListObjs = heroModule:GetHeroListByTargetStar(initStar + 1) or {}
    local list = {}
    for i,v in ipairs(canListObjs) do
        if not LxDataHelper:CheckIsSuperHero(v) then
            bLinkHeroObj = bLinkHeroMap[v.id]
            table.insert(list,{
                heroObj = v,
                isBLink = bLinkHeroObj ~= nil,
                bLinkObj = bLinkHeroObj,
            })
        end
    end
    return list
end

---@param heroObj LxHeroObj
---@return V_Item[] 升级消耗返回
function LxHeroCtrl:GetHeroReturnLevelItemList(heroObj)
    local level = heroObj.level
    if level < 1 then return {} end
    local isShare = ModuleCenter.Hero:CheckIsShareHero(heroObj.id)
    if not isShare then
        return {}
    end
    local resultList = {}
    local recordItemMap = {}
    ---@type V_HeroLevelRef
    local levelRef = nil
    for i = 1,level - 1 do
        levelRef = GameTable.CharacterLevelRef[i]
        if levelRef then
            local needItems = LxDataHelper.ParseItemList(levelRef.need)
            for _, v in ipairs(needItems) do
                if not recordItemMap[v.refId] then
                    recordItemMap[v.refId] = v.num
                else
                    recordItemMap[v.refId] = recordItemMap[v.refId] + v.num
                end

            end
        end
    end

    local tNum = 0
    for i,v in pairs(recordItemMap) do
        tNum = v
        if tNum and tNum > 0 then
            table.insert(resultList,{
                type = ThingType.Item,
                refId = i,
                num = tNum or 0,
            })
        end
    end
    return resultList
end

---@param heroObj LxHeroObj
---@return V_Item[] 进阶消耗返回
function LxHeroCtrl:GetHeroReturnGradeItemList(heroObj)
    local grade = heroObj.grade
    if grade < 1 then return {} end
    local itemMap = {}
    ---@type V_HeroClassRef
    local classRef = nil
    ---@type V_Item[]
    local classReturnList = {}
    local classId
    local classType = LxDataHelper.GetHeroClassType(heroObj.refId)
    for i = 0,grade - 1 do
        classId = LxDataHelper.GetClassId(classType,i)
        classRef = LxDataHelper.GetHeroClassRefByClassId()
        if classRef then
            classReturnList = self:GetHeroClassNeedItem(classRef)
            if classReturnList and #classReturnList > 0 then
                for idx,val in ipairs(classReturnList) do
                    local itemTypeMap = itemMap[val.type]
                    if not itemTypeMap then
                        itemTypeMap = {}
                        itemMap[val.type] = itemTypeMap
                    end
                    local itemNum = itemTypeMap[val.refId] or 0
                    itemTypeMap[val.refId] = itemNum + val.num
                end
            end
        end
    end
    local tempItemList = {}
    for type,typeData in pairs(itemMap) do
        for refId,num in pairs(typeData) do
            table.insert(tempItemList,{
                type = type,
                refId = refId,
                num = num
            })
        end
    end
    table.sort(tempItemList,function(a,b)
        return LxDataHelper.GetItemSort(a.refId) < LxDataHelper.GetItemSort(b.refId)
    end)
    return tempItemList
end

---@param heroObj LxHeroObj
---@param targetStar number 返回到指定的星级
---@return V_Item[] 升星消耗返回
function LxHeroCtrl:GetHeroReturnStarItemList(heroObj,targetStar)
    local initStar = LxDataHelper.GetHeroInitStar(heroObj.refId)
    local star = heroObj.star
    if star <= initStar then return {} end

    targetStar = targetStar or initStar
    if star < targetStar then return {} end

    local resultList = {}
    local refId = heroObj.refId
    local payItems
    local upStarAppoint,upStarRange,upStarItem
    local translateItems,item
    ---@type V_HeroStarRef
    local starRef = nil
    local startStar,endStar
    if targetStar >= star then
        startStar = initStar
        endStar = targetStar - 1
    else
        startStar = initStar
        endStar = star - 1
    end
    for i = startStar,endStar do
        starRef = LxDataHelper.GetHeroStarRefByRefIdAndStar(refId,i)
        if starRef then
            payItems = self:GetParseUpStarPayItemList(starRef)
            if payItems then
                upStarAppoint = payItems.upStarAppoint
                if upStarAppoint.isValid then
                    for idx,val in ipairs(upStarAppoint.list) do
                        for index = 1,val.payNum do
                            table.insert(resultList,{
                                type = ThingType.Hero,
                                refId = val.heroRefId,
                                star = val.star,
                            })
                        end
                    end
                end
                upStarRange = payItems.upStarRange
                if upStarRange.isValid then
                    for idx,val in ipairs(upStarRange.list) do
                        translateItems = CtrlCenter.Item:GetHeroMirrorItemByRaceTypeAndStar(val.heroRaceType,val.star)
                        if translateItems and #translateItems > 0 then
                            item = translateItems[1]
                            table.insert(resultList,{
                                type = ThingType.Item,
                                refId = item.refId,
                                num = val.payNum
                            })
                        end
                    end
                end
                upStarItem = payItems.upStarItem
                if upStarItem.isValid then
                    for idx,val in ipairs(upStarItem.list) do
                        table.insert(resultList,{
                            type = val.type,
                            refId = val.refId,
                            num = val.num,
                        })
                    end
                end
            end
        end
    end
    return resultList
end

