function LxHeroCtrl:GetInitHeroReturnRefListByRaceType(raceType)
    if not self._initHeroReturnRefMaps then
        self._initHeroReturnRefMaps = {}
    end
    local datas = self._initHeroReturnRefMaps[raceType]
    if not datas  then
        datas = {}
        for k,v in pairs(GameTable.CharacterReturnRef) do
            if v.race == raceType then
                datas[v.star] = {
                    refId = k,
                    race = raceType,
                    star = v.star,
                    returnStar = v.returnStar,
                    need = LxDataHelper.ParseItemStrList(v.need),
                    fixReward = LxDataHelper.ParseItemList(v.fixReward),
                    getNoumenonNum = v.getNoumenonNum,
                }
            end
        end
        self._initHeroReturnRefMaps[raceType] = datas
    end
    return datas
end

