function LxHeroCtrl:GetInitHeroGroupRef(type)
    if not self._initHeroGroupRefsByType then
        self._initHeroGroupRefsByType = {}
    end
    if not self._initHeroGroupRefsMap then
        self._initHeroGroupRefsMap = {}
    end
    ---@type V_HeroGroupRef[]
    local initHeroGroupRefTypes = self._initHeroGroupRefsByType[type]
    local initHeroGroupRefMap = self._initHeroGroupRefsMap[type]
    if not initHeroGroupRefTypes and not initHeroGroupRefMap then
        initHeroGroupRefTypes = {}
        for k,v in pairs(GameTable.HeroGroupRef) do
            if v.type == type then
                table.insert(initHeroGroupRefTypes,{
                    refId = k,
                    type = type,
                    unlock = v.unlock,
                    star = v.star,
                    attrAdd = LxDataHelper.ParseAttrList(v.attrAdd),
                })
            end
        end
        table.sort(initHeroGroupRefTypes,function(a,b) return a.refId < b.refId end)
        self._initHeroGroupRefsByType[type] = initHeroGroupRefTypes

        initHeroGroupRefMap = {}
        for i,v in ipairs(initHeroGroupRefTypes) do
            initHeroGroupRefMap[v.star] = v
        end
        self._initHeroGroupRefsMap[type] = initHeroGroupRefMap
    end
    return {
        refDatas = initHeroGroupRefTypes,
        refMap = initHeroGroupRefMap,
    }
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroBlessingListByHeroObj(heroObj)
    if not heroObj then return {} end

    local heroGroups = self:GetHeroGroupByHeroObj(heroObj)
    if not heroGroups or #heroGroups < 1 then return {} end

    local breakLevel = heroObj.breakLevel or 0
    local groupStar = heroObj.groupStar
    local groupStarMap = {}
    for i,v in ipairs(groupStar) do
        groupStarMap[v.key] = v.value
    end

    ---@type V_Attr
    local attr
    local attrRefId,attrName,attrValue
    local refData
    local refInfo,refDatas,refMap,isAct
    local heroRefId
    local tGroupStar
    local lockStr,attrAddStr
    local resultList = {}
    for i,v in ipairs(heroGroups) do
        refInfo = self:GetInitHeroGroupRef(v.blessingId)
        if refInfo then
            refDatas = refInfo.refDatas or {}
            refMap = refInfo.refMap
            heroRefId = v.heroRefId
            tGroupStar = groupStarMap[heroRefId]
            isAct = tGroupStar and tGroupStar > 0
            lockStr = ""
            attrAddStr = ""
            if isAct then
                refData = refMap[tGroupStar]
                if refData.attrAdd and #refData.attrAdd > 0 then
                    ---@type V_Attr
                    attr = refData.attrAdd[1]
                    if attr then
                        attrRefId = attr.refId
                        attrName = LxDataHelper.GetCombatAttributeName(attrRefId)
                        attrValue = LxDataHelper.ConvertAttrValue(attrRefId,attr.value)
                        attrAddStr = string.replace("#a1#+#a2#",attrName,attrValue)
                    end
                end
            else
                refData = refDatas[1] or {}
                tGroupStar = refData.star or -1
                lockStr = string.replace(I18nText(2576),refData.unlock or -1)
            end

            table.insert(resultList,{
                heroRefId = heroRefId,
                star = tGroupStar or 0,
                isAct = isAct,
                lockStr = lockStr,
                attrAddStr = attrAddStr,
            })
        end
    end
    return resultList
end

function LxHeroCtrl:GetHeroSoulSelList(params)
    local list = {}
    local heroRefId = params.heroRefId
