            })
        end
    end
    return list
end

---@param heroObj LxHeroObj
function LxHeroCtrl:GetHeroGroup1Ref(heroObj)
    if not self._initHeroGroup1RefsMap then
        self._initHeroGroup1RefsMap = {}
    end
    if not self._initHeroGroup1Map then
