---@param heroObj LxHeroObj
function LxHeroCtrl:GetSuperHeroBlessingSkill(heroObj)
    local groupLevel = heroObj.groupLevel
    local refInfo = self:GetHeroGroup1Ref(heroObj)
    local refMap = refInfo.refMap
    local refData = refMap[groupLevel]
    local isUnlock = refData ~= nil
    if not isUnlock then
        local refDatas = refInfo.refDatas
        if #refDatas > 0 then
            groupLevel = refDatas[1].level
        else
            groupLevel = groupLevel + 1
        end
        refData = refMap[groupLevel]
    end
    if not refData then return end

    local breakLevel = heroObj.breakLevel
    local unlock = refData.unlock
    local isOpen = breakLevel >= unlock
    local lockStr = ""
    if not isOpen then
        lockStr = string.replace(I18nText(2576),unlock)
    end
    return {
        isOpen = isOpen,
        lockStr = lockStr,
        refId = refData.refId,
        group = refData.group,
        level = refData.level,
        unlock = unlock,
        icon = refData.icon,
        name = refData.name,
        desc = refData.desc,
    }
end

---@param heroObj LxHeroObj
---@return number 状态  -2：淬炼等级不足，-1：满级，0：未定义，1：可以激活
function LxHeroCtrl:CheckIsCanActiveGroupState(heroObj)
    local groupLevel = heroObj.groupLevel + 1
    local refInfo = self:GetHeroGroup1Ref(heroObj)
    if not refInfo then return 0 end

    local refDatas = refInfo.refDatas
    if groupLevel > #refDatas then
        return -1
    end

    local refMap = refInfo.refMap
    local refData = refMap[groupLevel]
    if not refData then return 0 end

    local breakLevel = heroObj.breakLevel
    if breakLevel < refData.unlock then
        return -2,refData.unlock
    end

    return 1
end

