---@return number 返回所有英雄好感度总和
function LxHeroCtrl:GetHeroTableAllLoveValue()
    local value = 0
    local heroTableObjs = ModuleCenter.Hero:GetHeroTableObjs()
    for k,v in pairs(heroTableObjs) do
        value = value + v.loveValue
    end
    return value
