---@return number 返回所有英雄好感度等级
function LxHeroCtrl:GetHeroTableAllLoveLevel()
    local lv = 0
    local initHeroGoodAllRefList = self:InitHeroGoodAllRefList()
    if self:CheckIsFullLoveLv() then
        ---@type V_HeroGoodAllRef
        local lastRef = initHeroGoodAllRefList[#initHeroGoodAllRefList]
        return lastRef and lastRef.refId or -1
    end
    local value = self:GetHeroTableAllLoveValue()
    for i,v in ipairs(initHeroGoodAllRefList) do
        if v.need ~= -1 and value >= v.need then
            --- 如果等于当前升级需好感度，则等于下一个等级
            lv = v.refId + 1
        end
    end
    return lv
end

function LxHeroCtrl:CheckIsFullLoveLv()
    local value = self:GetHeroTableAllLoveValue()
    local initHeroGoodAllRefList = self:InitHeroGoodAllRefList()
    local len = #initHeroGoodAllRefList
    ---@type V_HeroGoodAllRef
    local maxNeedRef = initHeroGoodAllRefList[len - 1]
    local maxNeed = maxNeedRef and maxNeedRef.need or 999999
    return value >= maxNeed
end

function LxHeroCtrl:GetHeroTableLoveSchedule()
    if self:CheckIsFullLoveLv() then
        return 1,1
    else
        local value = self:GetHeroTableAllLoveValue()
        local lv = self:GetHeroTableAllLoveLevel()
        local ref = GameTable.HeroGoodAllRef[lv]
        if ref and ref.need > 0 and ref.need < value then
            lv = lv + 1
            ref = GameTable.HeroGoodAllRef[lv]
        end
        return value,ref and ref.need or -1
    end
end

function LxHeroCtrl:GetHeroGoodAllRefData()
    local lv = self:GetHeroTableAllLoveLevel()
    local ref = self:GetHeroGoodAllRefDataByRefId(lv)
    if not ref then
        local initHeroGoodAllRefList = self:InitHeroGoodAllRefList()
        ref = initHeroGoodAllRefList[#initHeroGoodAllRefList]
    end
    return ref
end

function LxHeroCtrl:GetHeroGoodActAttrList()
    local targetAttrs = {}
    local openLv
    local lv = self:GetHeroTableAllLoveLevel()
    local initHeroGoodAllRefList = self:InitHeroGoodAllRefList()
    for i,v in ipairs(initHeroGoodAllRefList) do
        if v.refId > lv and #v.targetAttr > 0 then
            targetAttrs = v.targetAttr
            openLv = v.refId
            break
        end
    end
    return targetAttrs,openLv
end

function LxHeroCtrl:GetMaxLoveSchedule()
    if not self._maxLoveSchedule then
        local maxLv = 0
        local need
        local initHeroGoodAllRefList = self:InitHeroGoodAllRefList()
        for i,v in ipairs(initHeroGoodAllRefList) do
            need = v.need
            if need and need > 0 then
                if maxLv < need then
                    maxLv = need
                end
            end
        end
        self._maxLoveSchedule = maxLv
    end
    return self._maxLoveSchedule
end

---@return string 获取当前的好感度进度
function LxHeroCtrl:GetCurLoveScheduleInfo()
    local value = self:GetHeroTableAllLoveValue()
    local lv = self:GetHeroTableAllLoveLevel()
    local ref = self:GetHeroGoodAllRefDataByRefId(lv)
    local need = ref and ref.need or 0
    if ref and need == -1 then
        need = self:GetMaxLoveSchedule()
    end
    return {
        curValue = value,
        needValue = need,
    }
end

