---@param heroObj LxHeroObj 等级大于100级后的升级，受材料限制
---@return table
---@field payItemList table 升级道具列表
---@field payClassItemList table 升阶道具列表
---@field state number 状态码 -4:已满级 ; -1:不可升级,0：可升级,1：升至满阶
---@field btnName string 按钮名字
---@field upLv number state 字段 == 0 或者 upLv == 1，返回升级数
function LxHeroCtrl:GetHeroUpMoreLvExpendListByHeroObj(heroObj)
    if not heroObj then return { state = -1, } end

    local heroCurMaxLv = LxDataHelper.GetHeroStarMaxLevelByHeroObj(heroObj)
    if heroCurMaxLv and heroObj:GetHeroLevel() >= heroCurMaxLv then
        return { state = -4, }
    end

    local lv = heroObj:GetHeroLevel()
    local tempMaxLv = self:GetGradeNeedMaxLevel()
    local maxLv = self:GetHeroClassMaxLvLimit(heroObj)
    local maxGrade = self:GetHeroClassMaxGradeByHeroObj(heroObj)
    if (maxLv and tempMaxLv >= maxLv and lv < maxLv) or maxGrade > heroObj:GetHeroGrade() then
        local tempData = self:GetHeroUpLv2MaxGradeExpendListByHeroObj(heroObj)
        if tempData and tempData.state == 1 then
            return tempData
        end
    end

    local classRef = LxDataHelper.GetHeroClassRefByHeroObj(heroObj)
    if not classRef then return { state = -1, } end

    if classRef.needLevel ~= -1 then return { state = -1, } end

    local heroStarRef = LxDataHelper.GetHeroStarRefByHeroObj(heroObj)
    if not heroStarRef then return { state = -1, } end

    local maxLevel = heroStarRef.maxLevel
    if lv >= maxLevel then return { state = -1, } end

    local minHeroLevel = ModuleCenter.Hero:GetMinLevelByHighestPowerHeroList(self._highestPowerHeroNum)

    local itemModule = ModuleCenter.Item
    local heroExpId = Item_Ids.HeroExp
    local silverId = Item_Ids.Silver

    local hasList = {}
    local needList = {}
    local payItems = {heroExpId,silverId}
    local hasNum
    --for i,itemId in ipairs(payItems) do
    --    hasNum = itemModule:GetItemCount(itemId)
    --    residueNumMap[itemId] = hasNum
    --    constNumMap[itemId] = hasNum
    --end

    maxLevel = maxLevel - 1
    local herolvShareDis = GameTable.CharacterConfigRef.herolvShareDis
    local upLv = 0
    local level = 0
    local tempLv = lv
    local lvRef,heroMaxLvDis
    local isMaxLvDis = false
    for i = tempLv, maxLevel do
        lvRef = GameTable.CharacterLevelRef[i]
        if not lvRef then break end

        isMaxLvDis = (tempLv - minHeroLevel) > herolvShareDis

        local oneList
        local itemId
        local needNum
        local needTotalNum = 0
        local canNum = 0
        local remaining = 0

        for k, v in pairs(lvRef.need) do
            oneList = string.split(v, "=")
            itemId = tonumber(oneList[2])
            needNum = tonumber(oneList[3])
            if not hasList[itemId] then
                hasNum = ModuleCenter.Item:GetItemCount(itemId)
                hasList[itemId] = hasNum
            end
            if not needList[itemId] then
                needList[itemId] = 0
            end
            remaining = hasList[itemId] - needList[itemId]
            needTotalNum = needTotalNum + 1
            if remaining >= needNum then
                canNum = canNum + 1
            end
        end

        if canNum >= needTotalNum and not isMaxLvDis then
            upLv = upLv + 1
            level = i
            for k, v in pairs(lvRef.need) do
                oneList = string.split(v, "=")
                itemId = tonumber(oneList[2])
                needNum = tonumber(oneList[3])
                needList[itemId] = needList[itemId] + needNum --- 加上一级的消耗
            end
        else
            break
        end
    end

    if upLv < 1 then return { state = -1, } end
    level = level + 1
    local payItemList = {}
    for i, v in pairs(needList) do
        table.insert(payItemList,{
            type = ThingType.Item,
            refId = i,
            num = v
        })
    end
    return {
        state = 0,
        payItemList = payItemList,
        btnName = string.replace(I18nText(2423),upLv),
        upLv = upLv,
        level = level,
    }
end

---@return V_HeroClassRef[] 返回对应的阶级类型列表
function LxHeroCtrl:InitClassTypeListByClassType(classType)
    local initClassTypeList = self._initClassTypeList
    if not initClassTypeList then
        initClassTypeList = {}
        self._initClassTypeList = initClassTypeList
    end
    local classTypeList = initClassTypeList[classType]
    if not classTypeList then
        classTypeList = {}
        for k,v in pairs(GameTable.CharacterClassRef) do
            if v.type == classType then
                table.insert(classTypeList,v)
            end
        end
        table.sort(classTypeList,function(a,b) return a.refId < b.refId end)
        initClassTypeList[classType] = classTypeList
    end
    return classTypeList
end

---@param heroObj LxHeroObj
---@return number 获取最大星级的等级
function LxHeroCtrl:GetHeroClassMaxLvLimit(heroObj)
    if not heroObj then return end

    local heroRefId = heroObj.refId
    local classType = LxDataHelper.GetHeroClassTypeByHeroRefId(heroRefId)
    if classType and classType > 0 then
        local initHeroClassMaxLvMap = self._initHeroClassMaxLvMap
        if not initHeroClassMaxLvMap then
            initHeroClassMaxLvMap = {}
            self._initHeroClassMaxLvMap = initHeroClassMaxLvMap
        end
        local maxLv = initHeroClassMaxLvMap[heroRefId]
        if not maxLv then
            local classTypeList = self:InitClassTypeListByClassType(classType)
            if classTypeList and #classTypeList > 0 then
                local needLevel
                local needStar
                for i,v in ipairs(classTypeList) do
                    needLevel = v.needLevel
                    if needLevel > 0 then
                        if not maxLv then
                            maxLv = needLevel
                        elseif needLevel > maxLv then
                            maxLv = needLevel
                        end
                        needStar = v.needStar
                    end
                end
                if needStar and needStar > 0 then
                    local starId = LxDataHelper.GetHeroStarId(heroRefId,needStar)
                    maxLv = LxDataHelper.GetHeroStarMaxLevel(starId)
                end
                self._initHeroClassMaxLvMap[heroRefId] = maxLv
            end
        end
        return maxLv
    end
end

function LxHeroCtrl:GetGradeNeedMaxLevel()
    if not self._gradeNeedMaxLevel then
        local maxLevel = 0
        local needLevel
        for k,v in pairs(GameTable.CharacterClassRef) do
            needLevel = v.needLevel
            if needLevel > 0 and needLevel > maxLevel then
                maxLevel = needLevel
            end
        end
        self._gradeNeedMaxLevel = maxLevel
    end
    return self._gradeNeedMaxLevel
end

---@param heroObj LxHeroObj
---@return number 返回阶级最大的星级限制
function LxHeroCtrl:GetHeroClassMaxStarLimit(heroObj)
    if not heroObj then return end

    local heroRefId = heroObj.refId
    local classType = LxDataHelper.GetHeroClassTypeByHeroRefId(heroRefId)
    if classType and classType > 0 then
        local initHeroClassMaxStarMap = self._initHeroClassMaxStarMap
        if not initHeroClassMaxStarMap then
            initHeroClassMaxStarMap = {}
            self._initHeroClassMaxStarMap = initHeroClassMaxStarMap
        end
        local maxStar = initHeroClassMaxStarMap[classType]
        if not maxStar then
            local classTypeList = self:InitClassTypeListByClassType(classType)
            if classTypeList and #classTypeList > 0 then
                local needStar
                for i,v in ipairs(classTypeList) do
                    needStar = v.needStar
                    if needStar > 0 then
                        if not maxStar then
                            maxStar = needStar
                        elseif needStar > maxStar then
                            maxStar = needStar
                        end
                    end
                end
                self._initHeroClassMaxStarMap[classType] = maxStar
            end
        end
        return maxStar
    end
end

