---@param heroObj LxHeroObj 直接升到满阶等级
---@return table
---@field payItemList table 升级道具列表
---@field payClassItemList table 升阶道具列表
---@field state number 状态码 -1:不可升级,0：可升级,1：升至满阶
---@field btnName string 按钮名字
---@field upLv number state 字段 == 0 或者 upLv == 1，返回升级数
function LxHeroCtrl:GetHeroUpLv2MaxGradeExpendListByHeroObj(heroObj)
    if not heroObj then return { state = -1, } end

    local classType = LxDataHelper.GetHeroClassTypeByHeroRefId(heroObj.refId)
    if not classType or classType < 1 then return { state = -1, } end

    local classTypeList = self:InitClassTypeListByClassType(classType)
    if not classTypeList or #classTypeList < 1 then return { state = -1, } end

    local lastClassTypeRef = classTypeList[#classTypeList]
    local lastGrade = lastClassTypeRef.grade
    if heroObj:GetHeroGrade() >= lastGrade then return { state = -1, } end

    local maxLv = 0
    local curHeroStar = heroObj.star
    local recordNeedItemMap = {}
    local classId = LxDataHelper.GetClassIdByHeroObj(heroObj)
    ---@type V_Item[]
    local needItem
    local recordItemNum
    local recordUpClassMap = {}
    ---@type boolean 可以直接升到满阶
    local isMaxGrade = true
    local maxStarLimit = 0
    local maxLevelLimit = 0
    local needStar = 0
    for i,v in ipairs(classTypeList) do
        if v.refId >= classId then
            needStar = v.needStar
            --- 星级只是限制升阶，但是等级可以达到
            local isEnoughStar = curHeroStar >= needStar
            if isEnoughStar then
                needItem = self:GetHeroClassNeedItem(v)
                local recordUpClassItemMap = {}
                for idx,val in ipairs(needItem) do
                    recordUpClassItemMap[val.refId] = val

                    recordItemNum = recordNeedItemMap[val.refId] or 0
                    recordNeedItemMap[val.refId] = recordItemNum + val.num
                end
                recordUpClassMap[v.refId] = recordUpClassItemMap
            else
                isMaxGrade = false
            end
            if v.needLevel > 0 then
                maxLv = v.needLevel
                maxLevelLimit = maxLv
            end
            if needStar > 0 then
                maxStarLimit = needStar
            end
            if not isEnoughStar then break end
        end
    end

    local lv = heroObj:GetHeroLevel()
    if maxLv < 1 then
        local classMaxLv = self:GetHeroClassMaxLvLimit(heroObj)
        if classMaxLv and classMaxLv > 0 and classMaxLv > lv then
            maxLv = classMaxLv
        else
            return { state = -1, }
        end
    end

    if isMaxGrade then
        local starMaxLv = self:GetHeroClassMaxLvLimit(heroObj)
        local tempMaxLv = self:GetGradeNeedMaxLevel()
        local heroStarMax = LxDataHelper.GetHeroMaxStarByHeroObj(heroObj)
        --- 英雄最大星级大于限制星级，使用阶级最大等级
        if heroStarMax > maxStarLimit then
            if tempMaxLv and tempMaxLv > maxLv then
                maxLv = tempMaxLv
            end
        else
            if starMaxLv > maxLv and starMaxLv > maxLevelLimit then
                maxLv = starMaxLv
            end
        end
    end

    local enoughNum,enoughAllNum = 0,0
    local hasNum
    local itemModule = ModuleCenter.Item
    --- 判断是否可以直接升满阶
    for itemId,needNum in pairs(recordNeedItemMap) do
        hasNum = itemModule:GetItemCount(itemId)
        if hasNum >= needNum then
            enoughNum = enoughNum + 1
        end
        enoughAllNum = enoughAllNum + 1
    end
    if enoughNum < enoughAllNum then return { state = -1, } end

    local minHeroLevel = ModuleCenter.Hero:GetMinLevelByHighestPowerHeroList(self._highestPowerHeroNum)
    local heroExpId = Item_Ids.HeroExp
    local silverId = Item_Ids.Silver
    --- 当前拥有的道具数量
    local constNumMap = {}
    --- 剩下道具数量
    local residueNumMap = {}
    local payItems = {}
    --local payItems = {heroExpId,silverId}
    --for i,itemId in ipairs(payItems) do
    --    hasNum = itemModule:GetItemCount(itemId)
    --    constNumMap[itemId] = hasNum
    --    if recordNeedItemMap[itemId] then
    --        hasNum = hasNum - recordNeedItemMap[itemId]
    --    end
    --    residueNumMap[itemId] = hasNum
    --end

    local upLv = 0
    local level = 0
    local needExp,needGold,heroMaxLvDis
    ---@type V_HeroLevelRef
    local lvRef
    ---@type V_Item
    local item = nil
    maxLv = maxLv - 1
    local count
    local total
    local owner
    local refId
    local needNum
    for i = lv,maxLv do
        lvRef = GameTable.CharacterLevelRef[i]
        if not lvRef then break end

        heroMaxLvDis = lvRef.heroMaxLvDis
        if heroMaxLvDis and heroMaxLvDis > 0 then
            if heroMaxLvDis < minHeroLevel then break end
        end

        count = 0
        total = #lvRef.need
        for i, v in ipairs(lvRef.need) do
            item = LxDataHelper.ParseItem(v)
            refId = item.refId
            needNum = item.num
            owner = ModuleCenter.Item:GetItemCount()
            if owner >= needNum then
                count = count + 1
            end
            residueNumMap[refId] = owner
            residueNumMap[refId] = residueNumMap[refId] - needNum
        end

        if count ~= total then
            break
        end

        --needExp = lvRef.need
        --if residueNumMap[heroExpId] < needExp then break end
        --
        --needGold = lvRef.needGold
        --if residueNumMap[silverId] < needGold then break end

        --residueNumMap[heroExpId] = residueNumMap[heroExpId] - needExp
        --residueNumMap[silverId] = residueNumMap[silverId] - needGold

        upLv = upLv + 1
        level = i
    end

    if level < maxLv then return { state = -1, } end

    local payItemMap = {}
    local payItemList = {}
    for i,itemId in ipairs(payItems) do
        payItemMap[itemId] = true
        table.insert(payItemList,{
            type = ThingType.Item,
            refId = itemId,
            num = constNumMap[itemId] - residueNumMap[itemId],
        })
    end

    local payClassItemList = {}
    for k,v in pairs(recordNeedItemMap) do
        if not payItemMap[k] then
            table.insert(payClassItemList,{
                type = ThingType.Item,
                refId = k,
                num = v,
            })
        end
    end
    level = level + 1
    return {
        state = 1,
        payItemList = payItemList,
        payClassItemList = payClassItemList,
        btnName = string.replace(I18nText(2589),level),
        upLv = upLv,
        level = level,
    }
end

function LxHeroCtrl:GetHeroRefGoodReward(heroRefId)
    if not self._initHeroRefGoodRewardMap then
       self._initHeroRefGoodRewardMap = {}
    end
    local heroRefGoodRewardMap = self._initHeroRefGoodRewardMap[heroRefId]
    if not heroRefGoodRewardMap then
        local heroRef = LxDataHelper.GetHeroRef(heroRefId)
        if heroRef and string.isvalid(heroRef.goodReward) then
            local goodReward = string.split(heroRef.goodReward,";")
            if #goodReward > 0 then
                heroRefGoodRewardMap = {}
                local loveLv,itemList
                for i,v in ipairs(goodReward) do
                    v = string.split(v,":")
                    loveLv = checknumber(v[1])
                    itemList = LxDataHelper.ParseItemStrList(v[2])
                    heroRefGoodRewardMap[loveLv] = itemList
                end
                self._initHeroRefGoodRewardMap[heroRefId] = heroRefGoodRewardMap
            end
        end
    end
    return heroRefGoodRewardMap
end



--- 是否需要刷新英雄红点
function LxHeroCtrl:CheckNeedRefreshHeroRP(changeItems)
    if not changeItems or #changeItems < 1 then return end

    if not self._splitHeroRedItem then
        local heroRedItem = GameTable.CharacterConfigRef["heroRedItem"]
        if heroRedItem and #heroRedItem > 0 then
            for i,v in ipairs(heroRedItem) do
                self._heroTrainItemMap[v] = true
            end
        end
        self._splitHeroRedItem = true
    end

    for i,v in ipairs(changeItems) do
        if self._heroTrainItemMap[v] then
            return true
        end
    end
    return false
end

function LxHeroCtrl:CheckHeroEnterRP()
    if CtrlCenter.HeroBook:CheckHeroBookEnterRP() then
        return true
    end
    if self:CheckHeroMainFormationRP() then
        return true
    end
    return false
end

function LxHeroCtrl:CheckHeroMainFormationRP()

    local formationData = ModuleCenter.Battle:GetFormation(BattleType.Adventure)    -- 阵容信息
    local heroModule = ModuleCenter.Hero
    if not table.isempty(formationData) then
        for _, v in pairs(formationData.positions) do
            ---@type LxHeroObj
            local heroObj = heroModule:GetHero(v.id)
            if self:CheckHeroTrainRP(heroObj) then
                return true
            end
        end
    end
    return false
end

---@param heroObj LxHeroObj
function LxHeroCtrl:CheckHeroTrainRP(heroObj)
    if not heroObj then return false end
    local equipCtrl = CtrlCenter.Equip
    --- 升级/升阶
    if self:CheckHeroIsCanUpLvOrUpGrade(heroObj) then
        return true
    end

    --- 升星
    if self:CheckHeroIsCanUpStar(heroObj) then
        return true
    end

    --- 是否为超凡英雄
    if LxDataHelper:CheckIsSuperHero(heroObj) then
        if self:CheckHeroIsCanUpSoul(heroObj) then
            return true
        end

        if self:CheckHeroIsCanActiveGroup(heroObj) then
            return true
        end
    end
    --- 装备
    if equipCtrl:CheckEquipRedByHeroObj(heroObj) then
        return true
    end
    --- 专属装备
    if self:CheckHeroEquipExcRed(heroObj) then
        return true
    end
    return false
end

---@param heroObj LxHeroObj 升级检测
function LxHeroCtrl:CheckHeroIsCanUpLvOrUpGrade(heroObj)
    local upLvInfo = self:GetHeroUpLvExpendListByHeroObj(heroObj,true)
    if upLvInfo then
        if upLvInfo.state == 0 or upLvInfo.state == 1 then
            return true
        end
    end
    return false
end

---@param heroObj LxHeroObj 升星检测
---@param useHeroIdMap table 已使用过的英雄id
--- 返回值：第一个为升星状态，第二个为升星收集的数据，第一个值为true时才会返回
function LxHeroCtrl:CheckHeroIsCanUpStar(heroObj,useHeroIdMap)
    if LxDataHelper.CheckHeroIsMaxStar(heroObj) then return false end

    local payItemData = self:GetUpStarPayItemData(heroObj)
    if payItemData then
        local heroModule = ModuleCenter.Hero
        local recordSelHeroIdMap = {
            [heroObj.id] = true
        }
        useHeroIdMap = useHeroIdMap or {}
        for k,v in pairs(useHeroIdMap) do
            recordSelHeroIdMap[k] = true
        end
        local appoints = {}
        local selNum = 0
        local payNum = 0
        local tempHeroList
        local upStarAppoint = payItemData.upStarAppoint
        if upStarAppoint.isValid then
            for i,v in ipairs(upStarAppoint.list) do
                selNum = 0
                payNum = v.payNum
                tempHeroList = heroModule:GetHeroListByRefIdAndStar(v.heroRefId,v.star,recordSelHeroIdMap)
                if #tempHeroList > 0 then
                    for _i,hero in ipairs(tempHeroList) do
                        if selNum >= payNum then break end
                        if not recordSelHeroIdMap[hero.id] then
                            recordSelHeroIdMap[hero.id] = true
                            selNum = selNum + 1
                            table.insert(appoints,hero.id)
                        end
                    end
                end
                if selNum < payNum then return false end
            end
        end

        local ranges = {}
        local itemCtrl = CtrlCenter.Item
        local itemModule = ModuleCenter.Item
        --- 防止重叠使用（范围消耗+道具消耗）
        local recordUseItemMap = {}
        --- 仅 范围消耗
        local recordRangeItemMap = {}
        local itemId,itemNum,tempRangeItem
        local heroRaceType,star
        local upStarRange = payItemData.upStarRange
        if upStarRange.isValid then
            for i,v in ipairs(upStarRange.list) do
                selNum = 0
                payNum = v.payNum
                heroRaceType = v.heroRaceType
                star = v.star
                tempHeroList = heroModule:GetHeroListByRaceTypeAndStar(heroRaceType,star,recordSelHeroIdMap)
                if #tempHeroList > 0 then
                    for _i,hero in ipairs(tempHeroList) do
                        if selNum >= payNum then break end
                        if not recordSelHeroIdMap[hero.id] then
                            recordSelHeroIdMap[hero.id] = true
                            selNum = selNum + 1
                            table.insert(ranges,hero.id)
                        end
                    end
                end
                if selNum < payNum then
                    local loseNum = payNum - selNum
                    local mirrorItemList = itemCtrl:GetHeroMirrorItemByRaceTypeAndStar(heroRaceType,star)
                    if not mirrorItemList or #mirrorItemList < 1 then return false end
                    for _i,data in ipairs(mirrorItemList) do
                        itemId = data.refId
                        itemNum = itemModule:GetItemCount(itemId)
                        if recordUseItemMap[itemId] then
                            itemNum = itemNum - recordUseItemMap[itemId]
                        end
                        if itemNum and itemNum > 0 then
                            if itemNum >= loseNum then
                                --- 数量远大于剩余数量，直接跳出
                                recordUseItemMap[itemId] = loseNum

                                tempRangeItem = recordRangeItemMap[itemId] or 0
                                recordRangeItemMap[itemId] = tempRangeItem + loseNum

                                selNum = payNum
                                loseNum = 0
                                break
                            else
                                loseNum = loseNum - itemNum
                                selNum = selNum + itemNum
                                recordUseItemMap[itemId] = itemNum

                                tempRangeItem = recordRangeItemMap[itemId] or 0
                                recordRangeItemMap[itemId] = tempRangeItem + itemNum
                            end
                        end
                    end
                end
                if selNum < payNum then return false end
            end
        end

        local upStarItem = payItemData.upStarItem
        if upStarItem.isValid then
            local rUseItemNum
            for i,v in ipairs(upStarItem.list) do
                itemId = v.refId
                itemNum = itemModule:GetItemCount(itemId)
                rUseItemNum = recordUseItemMap[itemId]
                if rUseItemNum and rUseItemNum > 0 then
                    itemNum = itemNum - rUseItemNum
                    recordUseItemMap[itemId] = rUseItemNum + v.num
                end
                if itemNum < v.num then return false end
            end
        end

        local rangeItems = {}
        for k,v in pairs(recordRangeItemMap) do
            table.insert(rangeItems,{
                refId = k,
                num = v,
            })
        end

        local retDatas = {
            useHeroIdMap = recordSelHeroIdMap,
            useItemIdMap = recordUseItemMap,
            appoints = appoints,
            ranges = ranges,
            rangeItems = rangeItems,
        }
        return true,retDatas
    end
end


---@param heroObj LxHeroObj 淬魂检测
function LxHeroCtrl:CheckHeroIsCanUpSoul(heroObj)
    local list = self:GetHeroBreakNeedListByHeroObj(heroObj)
    if #list > 0 then
        local recordSelHeroIdMap = { [heroObj.id] = true, }
        local heroModule = ModuleCenter.Hero
        local type,refId,tempHeroList
        local enoughNum = 0
        local selNum
        local allNum = 0
        for i,v in ipairs(list) do
            type = v.type
            if type == ThingType.Hero then
                refId = v.refId
                if refId and refId > 0 then
                    tempHeroList = heroModule:GetHeroListByRefIdAndStar(refId,v.initStar,recordSelHeroIdMap)
                    selNum = tempHeroList and #tempHeroList or 0
                    if selNum < v.payNum then break end
                    enoughNum = enoughNum + 1
                end
            end
            allNum = allNum + 1
        end
        return enoughNum >= allNum
    end
    return false
end

---@param heroObj LxHeroObj 佑护检测
function LxHeroCtrl:CheckHeroIsCanActiveGroup(heroObj)
    local state = self:CheckIsCanActiveGroupState(heroObj)
    return state == 1
end



