---@return table
---@field status number 状态：-1 无英雄可升级，-2 有符合星级的英雄但无材料，0 可升星
function LxHeroCtrl:AutoUpStarByStar(star)
    star = star or 4
    local recordUpStarNum = 0
    ---@type table<string,LxHeroObj>
    local recordUpStarIdMap = {}
    local heroList = ModuleCenter.Hero:GetHeroList()
    for k,v in pairs(heroList) do
        if not LxDataHelper.CheckHeroIsMaxStar(v) and v.star == star then
            recordUpStarIdMap[k] = v
            recordUpStarNum = recordUpStarNum + 1
        end
    end
    if recordUpStarNum < 1 then
        return { status = -1,upStarInfos = {}, }
    end

    local upStarInfoNum = 0
    local target = true
    local recordItemCountMap = {}
    local itemModule = ModuleCenter.Item
    local allUseHeroIdMap = {}
    local allUseItemIdMap = {}
    local upStarInfos = {}
    local hasNum
    for id,heroObj in pairs(recordUpStarIdMap) do
        if not target then break end

        if not allUseHeroIdMap[id] then
            local status,retDatas = self:CheckHeroIsCanUpStar(heroObj,allUseHeroIdMap)
            if status and retDatas then
                local useHeroIdMap = retDatas.useHeroIdMap or {}
                for k,v in pairs(useHeroIdMap) do
                    allUseHeroIdMap[k] = true
                end
                local useItemIdMap = retDatas.useItemIdMap or {}
                for k,v in pairs(useItemIdMap) do
                    local rSelNum = allUseItemIdMap[k] or 0
                    allUseItemIdMap[k] = rSelNum + v
                end
                for itemId,itemNum in pairs(allUseItemIdMap) do
                    hasNum = recordItemCountMap[itemId]
                    if not hasNum then
                        hasNum = itemModule:GetItemCount(itemId)
                        recordItemCountMap[itemId] = hasNum
                    end
                    if hasNum < itemNum then
                        target = false
                        break
                    end
                end
                if not target then break end

                table.insert(upStarInfos,{
                    id = id,
                    appoints = retDatas.appoints or {},
                    ranges = retDatas.ranges or {},
                    rangeItems = retDatas.rangeItems or {},
                })
                upStarInfoNum = upStarInfoNum + 1
            end
        end
    end

    if upStarInfoNum < 1 then
        return { status = -2,upStarInfos = {}, }
    end

    return { status = 0,upStarInfos = upStarInfos, }
end

