--- 获取对应英雄的 某个技能的全等级技能列表

function LxHeroCtrl:GetHeroSKillList(skillId, type)
    skillId = checknumber(skillId)
    local skillRefList = GameTable.SnakeSkillRef
    local slgSkillRefList = GameTable.SlgSkillRef
    local showList = {}
    if type == HeroSkillGroupTypeEnums.Hero then
        --- 技能规则 角色id + 技能编号 + 技能等级 + 效果编号
        local skillRef = skillRefList[skillId]
        local skills = skillId % 1000
        local heroId = math.floor(skillId / 1000)
        local _skillNum = math.floor(skills / 100)  -- 技能编号
        local _skillLv = 1 --math.floor(skills % 100 / 10)  -- 技能等级 从1级开始找
        local _skillBuff = math.floor(skills % 10)  -- 技能效果编号
        local _skillBeginId = heroId * 1000 + _skillNum * 100 + 10 + _skillBuff -- 对应技能的1级技能id
        local beginRef = skillRefList[_skillBeginId]
        if not beginRef then
            return showList
        end
        table.insert(showList, beginRef)
        local nextLv = beginRef.nextLv

        for i = 1, 999 do
            if nextLv <= 0 then
                break
            end
            local _t = skillRefList[nextLv]
            nextLv = _t.nextLv
            table.insert(showList, _t)
        end
    else
        local slgSkillRef = slgSkillRefList[skillId]
        local _curGroup = slgSkillRef.skillGroupId
        local _skillBeginId = skillId - slgSkillRef.level
        for i = 1, 999 do
            local _t = slgSkillRefList[_skillBeginId + i]
            if _t and _t.skillGroupId == _curGroup then
                table.insert(showList, _t)
            else
                break
            end

        end

    end
    return showList

end

-- 获取当前升星 解锁的技能
--- @param heroObj LxHeroObj
function LxHeroCtrl:GetCurUpStarUnlockSkill(heroObj)
    if table.isempty(heroObj) then
        return {}
    end
    local starId = LxDataHelper.GetHeroStarIdByHeroObj(heroObj)
    local skillList = self:_GetParseHeroStarSkillList(starId)
    --- 目前英雄技能只会通过升阶解锁，所以只遍历 slg技能

    local showList = {}
    for _, v in ipairs(skillList.skillArmyList) do
        if v.needGrade == heroObj.star then
            local _t = {}
            _t.skillType = HeroSkillGroupTypeEnums.Strategy
            _t.skillId = v.skillId
            table.insert(showList, _t)
        end
    end
    for _, v in ipairs(skillList.skillBuildList) do
        if v.needGrade == heroObj.star then
            local _t = {}
            _t.skillType = HeroSkillGroupTypeEnums.Operate
            _t.skillId = v.skillId
            table.insert(showList, _t)
        end
    end
    return showList
end




function LxHeroCtrl:GetHeroList(raceType, careerType, attackType)
    raceType = raceType or 0
    careerType = careerType or 0
    attackType = attackType or 0
    local _tData = {}
    local heroList =  {}
    local heroRef = GameTable.CharacterRef
    local mode = ModuleCenter.Hero:GetCurMode()
    ---@type LxHeroObj[]
    local serverList = ModuleCenter.Hero:GetSortHeroList(1)
    for i,v in ipairs(serverList) do
        table.insert(heroList,{
            refId = v.refId,
            heroObj = v,
            canAct = false,
        })
        _tData[v.refId] = true
    end
    if mode == HeroModeType.Compete then
        for i, v in pairs(heroRef) do
            if not _tData[v.refId] then
                table.insert(heroList,{
                    refId = v.refId,
                    canAct = true,
                })
            end
        end
    end
    local showList = {}
    --local list = {}
    local refId
    for i,v in ipairs(heroList) do
        refId = v.refId
        if raceType == 0 or raceType == LxDataHelper.GetHeroRaceType(refId) then
            if careerType == 0 or careerType == LxDataHelper.GetHeroCareerType(refId) then
                if attackType == 0 or attackType == LxDataHelper.GetHeroActType(refId) then
                    if heroRef[refId] ~= nil and GameTable.CharacterEffectRef[refId] ~= nil then
                        table.insert(showList,v)
                        --if not v.canAct then
                        --    table.insert(list,v.heroObj)
                        --end
                    end
                end
            end
        end
    end
    local formationData = ModuleCenter.Battle:GetFormation(BattleType.Adventure)    -- 阵容信息
    local pos = {}
    if not table.isempty(formationData) then
        for _, v in pairs(formationData.positions) do
            pos[v.id] = 1
        end
    end

    self:SortHeroList(showList, pos, heroRef, mode == HeroModeType.Snake)
    return serverList, showList
end
--- 排序规则： 主线上阵 > 星级 > 品质 > 英雄refId > 英雄唯一id
--- @param positions table 主线冒险上阵列表
function LxHeroCtrl:SortHeroList(showList, positions, heroRef, isSnakeMode)
    local sortFunc = function(a, b)
        local aRef = heroRef[a.refId]
        local bRef = heroRef[b.refId]
        local aInfo = a.heroObj
        local bInfo = b.heroObj
        local aPosV = (aInfo and positions[aInfo.id]) and 1000000000 or 0
        local bPosV = (bInfo and positions[bInfo.id]) and 1000000000 or 0
        local aSort = not a.canAct and 100000000 or 0
        local bSort = not b.canAct and 100000000 or 0
        if isSnakeMode then
            aSort = aInfo.star * 1000000 + aPosV
            bSort = bInfo.star * 1000000 + bPosV
            aSort = aSort + ((aInfo.quality == 0 and aRef.quality or aInfo.quality) * 100000)
            bSort = bSort + ((bInfo.quality == 0 and bRef.quality or bInfo.quality) * 100000)
        else
            aSort = aSort + aRef.initStar * 1000000 + aPosV
            bSort = bSort + bRef.initStar * 1000000 + bPosV
            aSort = aSort + (aRef.quality * 100000)
            bSort = bSort + (bRef.quality * 100000)
        end

        aSort = aSort + a.refId
        bSort = bSort + b.refId

        if aSort ~= bSort then
            return aSort > bSort
        else
            if isSnakeMode then
                return checknumber(aInfo.id) > checknumber(bInfo.id)
            else
                return a.refId > b.refId
            end
        end
    end
    table.sort(showList, sortFunc)
end


--- 获取英雄战力 竞品模式下 使用这个接口
--- 英雄战力=等级战力 + 星级战力 + 技能战力 + 装备战力 +……+（后续拓展增加）
--- 等级战力=等级基础战力 * 战力加成 * 阶级战力加成 + 阶级基础战力 + 皮肤战力加成 + 皮肤图鉴战力加成 + 英雄图鉴战力加成
--- 星级战力=星级基础战力 * 战力加成
--- @param heroObj LxHeroObj
function LxHeroCtrl:GetHeroPower(heroObj)
    if not heroObj then
        return 0
    end
    local refId = heroObj.refId
    local heroRef = LxDataHelper.GetHeroRef(refId)
    local heroLvRef = GameTable.CharacterLevelRef[heroObj.level]
    local starId = LxDataHelper.GetHeroStarId(refId, heroObj.star)
    local starRef = LxDataHelper.GetHeroStarRef(starId)
    local skillRefList = GameTable.SnakeSkillRef
    local slgSkillRefList = GameTable.SlgSkillRef
    --local classType = LxDataHelper.GetHeroClassTypeByHeroRefId(refId)
    --local classId = LxDataHelper.GetClassId(classType, heroObj.grade)
    --local classRef = LxDataHelper.GetHeroClassRefByClassId(classId)
    local showPower = 0
    --- 等级战力
    local lvPower = 0
    --- 星级战力
    local starPower = 0
    --- 技能战力
    local skillPower = 0
    --- 装备战力
    local equipPower = 0
    --- 专属装备战力
    local excPower = self:GetHeroEquipExcPower(heroRef.equipExc, 0)

    --- 阶级战力加成 目前暂时不需要计算阶级
    local classRate = 1
    --- 阶级基础战力
    local classPower = 0
    --- 皮肤战力加成
    local skinPower = 0
    --- 皮肤图鉴战力加成
    local skinBook = 0
    --- 英雄图鉴战力加成
    local heroBook = 0

    lvPower = heroRef.powerLv * heroLvRef.powerRate * classRate + classPower + skinPower + skinBook + heroBook
    starPower = heroRef.powerStar * starRef.powerRate
    for i, v in ipairs(starRef.skillGroup) do
        local skills = string.split(v, "=")
        local ref = skillRefList[checknumber(skills[1])]
        skillPower = skillPower + ref.powerSkill
    end
    local skillList = self:GetCurUpStarUnlockSkill(heroObj)
    for i, v in ipairs(skillList) do
        local ref = slgSkillRefList[v.skillId]
        skillPower = skillPower + ref.power
    end

    showPower = lvPower + starPower + skillPower
    return showPower
end
--- 获取英雄专属装备战力
--- @param equipExcId number 专属装备id
--- @param level number 装备等级
function LxHeroCtrl:GetHeroEquipExcPower(equipExcId, level)
    if not equipExcId or equipExcId <= 0 or level == 0 then
        return 0
    end
    local excRef = GameTable.EquipExcRef[equipExcId]
    local lvRef = GameTable.EquipExcLvRef[level]
    local skillPower = 0
    local skillList = self:GetHeroExcSkill(equipExcId, level)
    local skillRefList = GameTable.SnakeSkillRef
    local slgSkillRefList = GameTable.SlgSkillRef
    for _, v in ipairs(skillList) do
        if v.unlockLv <= level then
            if v.skillType == HeroSkillGroupTypeEnums.Hero then
                local skillRef = skillRefList[v.skillId]
                skillPower = skillPower + skillRef.powerSkill
            else
                local skillRef = slgSkillRefList[v.skillId]
                skillPower = skillPower + skillRef.power
            end
        end
    end
    return excRef.power * lvRef.power + skillPower
end

--- 获取英雄身上穿戴的装备的总战力
--- @param heroObj LxHeroObj
function LxHeroCtrl:GetHeroEquipPower(heroObj)
    local equipPower = 0
    local equips = heroObj.equips or {}
    local eqModule = ModuleCenter.Equip
    for i, v in ipairs(equips) do
        if v ~= "0" then
            --- @type LxEquipObj
            local equipObj = eqModule:GetEquipInfo(v)
            equipPower = equipPower + equipObj.power
        end
    end
    return equipPower
end
--- 获取英雄专属装备 属性列表
function LxHeroCtrl:GetHeroExcAttr(equipExcId, level, isShowNext)
    local excRef = GameTable.EquipExcRef[equipExcId]
    local lvRef = GameTable.EquipExcLvRef[level]
    if level == excRef.maxLv then
        isShowNext = false
    end
    local nextLvRef
    if isShowNext then
        nextLvRef = GameTable.EquipExcLvRef[level + 1]
    end
    local excLvAddRefList = GameTable.EquipExcLvAddRef
    local showList = {}
    local parseAttr = LxDataHelper.ParseAttrStr(excRef.attr)
    local parseAttr2 = LxDataHelper.ParseAttrStr(excRef.attr1)
    for i, v in ipairs(parseAttr) do
        parseAttr[i].nextValue = 0
        if isShowNext then
            parseAttr[i].nextValue = v.value * nextLvRef.attrAdd
        end
        v.value = v.value * lvRef.attrAdd
        table.insert(showList, v)
    end
    for i, v in ipairs(parseAttr2) do
        parseAttr2[i].nextValue = 0
        if isShowNext then
            parseAttr2[i].nextValue = v.value * nextLvRef.attrAdd1
        end
        v.value = v.value * lvRef.attrAdd1
        table.insert(showList, v)
    end
    --- 附加属性 策划说目前规划用不到
    --local parseAttr3
    --for i, v in ipairs(excLvAddRefList) do
    --    if v.equipExcId == equipExcId then
    --        if v.level > level then
    --            break
    --        end
    --        if v.level == level then
    --            parseAttr3 = LxDataHelper.ParseAttrStr(v.attrAdd)
    --            break
    --        end
    --    end
    --end
    return showList
end

--- 根据等级 获取对应的技能显示
function LxHeroCtrl:GetHeroExcSkill(equipExcId, level)
    local excRef = GameTable.EquipExcRef[equipExcId]
    local showList = {}
    local heroSkill
    local slgSkill
    for i, v in ipairs(excRef.heroSkill) do
        local arr = string.split(v, "=")
        local skillId = checknumber(arr[1])
        local unlockLv = checknumber(arr[2])
        if (level < unlockLv and i == 1) or level >= unlockLv then
            heroSkill = {skillId = skillId, unlockLv = unlockLv, skillLv = i, skillType = HeroSkillGroupTypeEnums.Hero}
            if level < unlockLv then
                break
            end
        end
    end
    for i, v in ipairs(excRef.slgSkill) do
        local arr = string.split(v, "=")
        local skillId = checknumber(arr[1])
        local unlockLv = checknumber(arr[2])
        if (level < unlockLv and i == 1) or level >= unlockLv then
            slgSkill = {skillId = skillId, unlockLv = unlockLv, skillLv = i, skillType = HeroSkillGroupTypeEnums.Strategy}
            if level < unlockLv then
                break
            end
        end
    end
    if heroSkill then
        table.insert(showList, heroSkill)
    end
    if slgSkill then
        table.insert(showList, slgSkill)
    end
    return showList
end

--- 单个英雄的专属装备红点
--- @param heroObj LxHeroObj
function LxHeroCtrl:CheckHeroEquipExcRed(heroObj)
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.EquipExc)
    if not isOpen then
        return false
    end
    if table.isempty(heroObj) or string.isempty(heroObj.id) then
        return false
    end
    if CtrlCenter.Formation:CheckHeroIsInnerIns(heroObj) then
        local heroRef = heroObj.heroRef
        local equipExcId = heroRef.equipExc
        if equipExcId <= 0 then
            return false
        end
        local excRef = GameTable.EquipExcRef[equipExcId]
        local itemModule = ModuleCenter.Item
        local level = heroObj.equipExcLevel
        if level >= excRef.maxLv then
            return false
        end
        local lvRef = GameTable.EquipExcLvRef[level]
        local itemParse = LxDataHelper.ParseItemList(lvRef.upNeedItem)
        for _, v in ipairs(itemParse) do
            local hasNum = itemModule:GetItemCount(v.refId)
            if hasNum < v.num then
                return false
            end
        end
        return true
    end
    return false
end



return LxHeroCtrl